INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('15-customer-journey',2,15,'CUSTOMER JOURNEY','Hanh trinh khach hang',15,'draft','2026-06-20T12:05:24Z','2026-06-20T12:05:24Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4fa5d058-7b3e-4c65-8430-dc83eec4a785','15-customer-journey',NULL,2,'15.1 Mục tiêu quản trị: trả lời 7 câu hỏi quan trọng','151-muc-tieu-quan-tri-tra-loi-7-cau-hoi-quan-trong',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90cd637c-be6c-446e-9b1c-4551222ab546','4fa5d058-7b3e-4c65-8430-dc83eec4a785',0,'text','Sau khi đã nắm trong tay từng mảnh ghép rời rạc—từ Content, Ads, CRM, Sales, cho đến Clinic System và khối Tài sản niềm tin (Trust Assets) - đã đến lúc chúng ta cần một bản thiết kế tổng thể để ráp nối tất cả lại với nhau. Đó chính là **Customer Journey Map (Bản đồ hành trình khách hàng)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1fe86124-ec26-4b25-bf0b-81801ac1235c','4fa5d058-7b3e-4c65-8430-dc83eec4a785',1,'text','Trong hệ điều hành Dental Empire OS, hành trình của một khách hàng không bao giờ là một đường thẳng ngắn ngủi chỉ bao gồm việc "nhìn thấy quảng cáo → đặt lịch → điều trị". Đó là một sự dịch chuyển tâm lý phức tạp. Nếu muốn lan tỏa thành công tinh thần giúp cộng đồng thực sự hiểu và *thích làm răng*, chúng ta phải thiết kế một chuỗi điểm chạm có chủ đích, dẫn dắt họ từ một người lạ hoàn toàn trở thành một đại sứ thương hiệu trung thành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5337073-449c-4137-9493-9b602303dcb2','4fa5d058-7b3e-4c65-8430-dc83eec4a785',2,'image',NULL,'book/15-customer-journey/8424038d-5a4b-43ef-b00c-72fa838fbb1a-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('424cdd66-1e33-446f-8098-3f57c86203da','4fa5d058-7b3e-4c65-8430-dc83eec4a785',3,'text','Một bản đồ hành trình khách hàng tốt không phải để treo tường cho đẹp. Nó là công cụ quản trị thực chiến. Bằng cách chiếu hệ thống phòng khám vào tấm bản đồ này, người vận hành (Founder/Quản lý) sẽ lập tức nhìn thấu bức tranh kinh doanh và trả lời được 7 câu hỏi sinh tử:- **Khách hàng đang bị kẹt ở tầng nào?** (Họ hỏi giá rất nhiều ở tầng Relationship nhưng không bước sang tầng Conversion).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('27469d20-89cd-4556-ba6e-84a1228a1006','4fa5d058-7b3e-4c65-8430-dc83eec4a785',4,'text','- **Họ đang nghĩ gì, sợ gì, cần gì ở điểm chạm đó?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('42b1d019-26e3-4eef-9ab3-b8bec985b7ca','4fa5d058-7b3e-4c65-8430-dc83eec4a785',5,'text','(Sợ đau, sợ đắt, hay sợ bác sĩ thiếu kinh nghiệm).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a8659739-e0f1-4cca-9a41-022f802b85b3','4fa5d058-7b3e-4c65-8430-dc83eec4a785',6,'text','- **Kênh truyền thông nào đang phụ trách tầng đó?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('233c0caf-0074-4f1d-aa57-b10b55daf283','4fa5d058-7b3e-4c65-8430-dc83eec4a785',7,'text','(TikTok để kéo Traffic, Google Maps để chốt Search Layer).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba8fa83a-d551-40fb-bd65-994674af1ba1','4fa5d058-7b3e-4c65-8430-dc83eec4a785',8,'text','- **Loại nội dung nào cần phải xuất hiện đúng lúc?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14146f3c-5ad6-4acd-9313-653230bdbd5c','4fa5d058-7b3e-4c65-8430-dc83eec4a785',9,'text','(Cần tung Case thật ở tầng Authority Check, tung Review ở tầng Search Layer).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e4690bbd-c274-4bcc-bcf2-f384f674d373','4fa5d058-7b3e-4c65-8430-dc83eec4a785',10,'text','- **Ai trong đội ngũ chịu trách nhiệm chính?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b60c741c-7ce1-49d6-83f7-5f086f41aeb1','4fa5d058-7b3e-4c65-8430-dc83eec4a785',11,'text','(Đội Media lo phần Trust, đội Telesale lo phần Conversion, đội Bác sĩ/Trợ thủ lo phần Patient Experience).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80f69e5b-2bed-49e6-ab6b-ced0dac610fb','4fa5d058-7b3e-4c65-8430-dc83eec4a785',12,'text','- **Bộ KPI nào cần được đưa lên Dashboard để đo lường?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('12d9f13a-6eaa-42f9-ac94-44ad9ccf04d1','4fa5d058-7b3e-4c65-8430-dc83eec4a785',13,'text','(Đo CPL ở tầng trên, đo Booking Rate ở tầng giữa, đo Referral Rate ở tầng cuối).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('974f67ae-fe4a-47e6-a636-c3bb5d5ee9b7','4fa5d058-7b3e-4c65-8430-dc83eec4a785',14,'text','- **Lỗ hổng (Leak) đang nằm ở đâu khiến phòng khám đánh rơi khách hàng?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('317207da-e4e9-4775-bb58-26f2dc3956fa','4fa5d058-7b3e-4c65-8430-dc83eec4a785',15,'text','(Lead về nhiều nhưng chốt kém chứng tỏ lỗ hổng ở khâu Sales, chốt tốt nhưng không có khách cũ quay lại chứng tỏ lỗ hổng ở Patient Experience và CSKH).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('52484e36-4961-47bd-94de-49e602f25ab5','15-customer-journey',NULL,2,'15.2 Sự đồng bộ: chiếc cầu nối với các Dental OS','152-su-ong-bo-chiec-cau-noi-voi-cac-dental-os',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56899cd1-4451-4d38-9154-3da1d7627b9f','52484e36-4961-47bd-94de-49e602f25ab5',16,'text','Khách hàng không bao giờ quan tâm phòng khám của bạn có bao nhiêu phòng ban. Thứ duy nhất họ cảm nhận là sự mượt mà của trải nghiệm. Vì vậy, Customer Journey Map đóng vai trò là "chiếc cầu nối" xóa bỏ ranh giới giữa các bộ phận, hợp nhất mọi cỗ máy lại với nhau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d89a93b6-e413-4df5-9292-9f7b502d0d83','52484e36-4961-47bd-94de-49e602f25ab5',17,'text','- **Marketing OS:** Phụ trách bơm nhiên liệu vào phần đầu của bản đồ (Traffic → Trust → Relationship → Authority Check).- **Sales OS:** Tiếp quản khúc cua quyết định để tạo ra doanh thu (Search Layer → Conversion).- **Clinic OS & Patient OS:** Làm chủ vùng lõi chuyên môn để giữ trọn lời hứa thương hiệu (Patient Experience).- **Referral OS:** Kích hoạt vòng lặp tăng trưởng vô hạn ở phần đuôi bản đồ (Review → Referral → Retention).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a7e4b85-3423-408b-a56b-b07e10c4606d','52484e36-4961-47bd-94de-49e602f25ab5',18,'text','Khi làm chủ được Bản đồ hành trình này, mọi nội dung (Content), kịch bản chốt sale (Sales Script), quy trình vận hành (SOP) hay thiết lập CRM đều sẽ có một hệ quy chiếu chung. Bạn không còn điều hành phòng khám trong bóng tối, mà đang cầm trên tay một la bàn định vị chính xác từng bước đi của dòng tiền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3e8670db-a6c9-4844-be0a-2973f50960cd','15-customer-journey',NULL,2,'15.3 Năm mục tiêu chiến lược của Customer Journey','153-nam-muc-tieu-chien-luoc-cua-customer-journey',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('26ef3503-da33-41ca-bbbd-41ab39c8561d','3e8670db-a6c9-4844-be0a-2973f50960cd',19,'text','Khi bắt tay vào vẽ Bản đồ hành trình khách hàng (Customer Journey Map), nhiều người trong đội ngũ của tôi từng nghĩ đây chỉ là một bài tập lý thuyết của phòng Marketing. Nhưng tôi đã chứng minh cho họ thấy điều ngược lại: Đây là chiếc xương sống của toàn bộ hệ thống vận hành. Nếu không có tấm bản đồ này, chúng ta sẽ liên tục đưa ra những quyết định mù mờ dựa trên cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6940da90-b864-49f6-979a-30cc212eccf1','3e8670db-a6c9-4844-be0a-2973f50960cd',20,'text','Về mặt quản trị, việc xây dựng và ứng dụng Customer Journey Map nhằm hiện thực hóa 5 mục tiêu chiến lược sau đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('71172b60-1822-4172-bbbb-894e9b2ce42e','15-customer-journey','3e8670db-a6c9-4844-be0a-2973f50960cd',3,'Chuẩn Hóa Tư Duy Toàn Đội Ngũ (Standardize the Journey)','chuan-hoa-tu-duy-toan-oi-ngu-standardize-the-journey',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da40d940-3914-481b-8abf-80cd17060442','71172b60-1822-4172-bbbb-894e9b2ce42e',21,'text','Mục tiêu đầu tiên và quan trọng nhất là đập tan tư duy "mì ăn liền" trong nội bộ phòng khám. Tôi luôn nhấn mạnh với nhân viên rằng: Bệnh nhân không tự nhiên nhìn thấy một bài đăng rồi lập tức nhấc máy đặt lịch hẹn ngay. Đằng sau một quyết định can thiệp vào cơ thể (như niềng răng hay cắm implant) là một chuỗi diễn biến tâm lý cực kỳ phức tạp. Việc chuẩn hóa hành trình giúp từ bạn thiết kế nội dung, bạn chạy Ads cho đến bạn Telesale hiểu được khách hàng đang ở đâu, họ cần thời gian để chuyển hóa từ e ngại sang tin tưởng, và cuối cùng mới thực sự **thích làm răng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a9abb010-b416-40f5-81b7-a05051efd850','15-customer-journey','3e8670db-a6c9-4844-be0a-2973f50960cd',3,'Bịt Kín Các Lỗ Hổng "Rơi Khách" (Leak Control)','bit-kin-cac-lo-hong-roi-khach-leak-control',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('701b5c9d-a773-4171-8eac-1ff60b360440','a9abb010-b416-40f5-81b7-a05051efd850',22,'text','Trong kinh doanh nha khoa, việc "đốt tiền" mang lead về thì dễ, nhưng giữ được lead đi hết hành trình mới là bài toán khó. Mỗi một tầng chuyển đổi đều là một khúc cua nguy hiểm, nơi khách hàng có thể lặng lẽ rời bỏ bạn để sang đối thủ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2e63897-af51-4048-a426-dc22f5ddc0e1','a9abb010-b416-40f5-81b7-a05051efd850',23,'text','- **Lỗ hổng 1:** Có lượng tương tác khủng (**Traffic**) nhưng fanpage trống rỗng, không tạo được niềm tin (**Trust**).- **Lỗ hổng 2:** Khách nhắn tin inbox hỏi bài bản nhưng tốc độ phản hồi của Sales quá chậm.- **Lỗ hổng 3:** Tư vấn y khoa rất hay nhưng không biết cách đưa ra lời mời chốt lịch hẹn (**Booking**).- **Lỗ hổng 4:** Khách đã hẹn ngày giờ nhưng phòng khám quên nhắc lịch, dẫn đến việc trống ghế (**No-show**).- **Lỗ hổng 5:** Điều trị cho khách rất đẹp nhưng kết thúc ca là xong, không chủ động xin đánh giá (**Review**).- **Lỗ hổng 6:** Khách hàng khen nức nở nhưng phòng khám không có cơ chế để kích hoạt sự giới thiệu (**Referral**).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bb82467-a892-4a37-9fda-58250bf99e50','a9abb010-b416-40f5-81b7-a05051efd850',24,'text','Customer Journey Map giúp bạn định vị chính xác vị trí "chiếc thùng đang bị thủng đáy" để kịp thời vá lại, tối ưu hóa từng đồng chi phí marketing.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8a383a49-6c98-45c6-96c6-f9a00b317dd0','15-customer-journey','3e8670db-a6c9-4844-be0a-2973f50960cd',3,'Gắn Đúng Nội Dung Với Đúng Giai Đoạn (Context-Driven Content)','gan-ung-noi-dung-voi-ung-giai-oan-context-driven-content',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('55956a3f-51fa-47a3-ba42-31d5c200ec12','8a383a49-6c98-45c6-96c6-f9a00b317dd0',25,'text','Một sai lầm kinh điển là dùng chung một thông điệp cho mọi nhóm khách hàng. Khách hàng ở tầng *Traffic* (người lạ) cần những nội dung giáo dục thị trường, khơi gợi nỗi đau một cách nhẹ nhàng. Nếu bạn lập tức ném vào mặt họ một chương trình giảm giá sốc, họ sẽ đề phòng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10758df7-6215-480d-8feb-564b4c79dd86','8a383a49-6c98-45c6-96c6-f9a00b317dd0',26,'text','Ngược lại, một khách hàng đã ở tầng *Search Layer* (đang chủ động so sánh) thì thứ họ cần là Case thật, là hồ sơ năng lực của Bác sĩ và các Review 5 sao, chứ không phải là những bài viết định nghĩa "Implant là gì". Bản đồ này giúp chúng ta "gãi đúng chỗ ngứa" của khách hàng tại từng thời điểm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('26a66fde-4429-47e6-bba2-3099cdcc5a22','15-customer-journey','3e8670db-a6c9-4844-be0a-2973f50960cd',3,'Thiết Lập Hệ Thống KPI Dẫn Đường (Journey KPIs)','thiet-lap-he-thong-kpi-dan-uong-journey-kpis',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b75a7544-640d-4255-a0ad-f9d2d56f4763','26a66fde-4429-47e6-bba2-3099cdcc5a22',27,'text','Nếu bạn chỉ nhìn vào con số doanh thu cuối tháng để đánh giá hiệu quả phòng khám, bạn đang đi lùi. Doanh thu là chỉ số muộn (Lagging Indicator). Để chủ động kiểm soát vận hành, chúng ta phải theo dõi các chỉ số dẫn đường (Leading Indicators) dọc theo hành trình khách hàng. Customer Journey Map chia nhỏ dòng chảy này ra để bạn đo lường: tỷ lệ chuyển đổi từ Traffic sang Inbox là bao nhiêu? Từ Inbox sang Booking là bao nhiêu? Từ Booking sang Show-up là bao nhiêu? Khi các chỉ số thành phần này tốt, doanh thu cuối cùng tự động sẽ bùng nổ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3dd1f47b-57f1-4dac-aea3-423eb3b58fd6','15-customer-journey','3e8670db-a6c9-4844-be0a-2973f50960cd',3,'Đặt Nền Móng Cho Hệ Thống CRM Và Automation (The Blueprint for System)','at-nen-mong-cho-he-thong-crm-va-automation-the-blueprint-for-system',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc140f99-5fad-4379-bef5-0378e788f1da','3dd1f47b-57f1-4dac-aea3-423eb3b58fd6',28,'text','Cuối cùng, bản đồ này chính là bản thiết kế kỹ thuật (Blueprint) để chúng ta lập trình công nghệ. Bạn không thể thiết kế các giai đoạn (Stages) trên đường ống CRM, không thể viết các kịch bản tin nhắn tự động (Automation), hay cài đặt lịch nhắc gọi lại (Recall) nếu không biết rõ hành trình của bệnh nhân đi qua những điểm chạm nào. Khách hàng đi đến đâu trên bản đồ, hệ thống CRM và các dòng lệnh Automation sẽ tự động kích hoạt đến đó để hỗ trợ con người một cách hoàn hảo nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39ad1f03-767b-4c3f-8caf-7db72f55533d','3dd1f47b-57f1-4dac-aea3-423eb3b58fd6',29,'text','**Tóm lại:** Customer Journey Map không phải là một bức tranh nghệ thuật để ngắm nhìn. Nó là chiếc la bàn giúp toàn bộ bộ máy từ Marketing, Sales, Clinic cho đến CSKH nhìn về cùng một hướng, hành động đồng bộ và biến trải nghiệm của bệnh nhân thành một chuỗi những điểm chạm hạnh phúc, mang lại sự tăng trưởng bền vững cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('295f11f6-925a-4822-a42f-58ed4493a401','15-customer-journey',NULL,2,'15.4 Chuỗi điểm chạm chiến lược của Dental Empire','154-chuoi-iem-cham-chien-luoc-cua-dental-empire',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a78ee851-1fe7-4c97-afcd-bdc3a82ba708','295f11f6-925a-4822-a42f-58ed4493a401',30,'image',NULL,'book/15-customer-journey/6eadc15d-5005-4398-b8ae-e293043e9d1c-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('070ab753-fe19-41c6-bd23-c8e5568519be','15-customer-journey',NULL,2,'15.5 Năm nguyên tắc vàng thiết kế Customer Journey thực chiến','155-nam-nguyen-tac-vang-thiet-ke-customer-journey-thuc-chien',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a23b2f23-5211-4cd1-b414-f9c19e383950','070ab753-fe19-41c6-bd23-c8e5568519be',31,'text','Vẽ ra một tấm bản đồ hành trình khách hàng đẹp mắt trên giấy thì ai cũng làm được. Nhưng để biến tấm bản đồ đó thành một hệ điều hành sống động, giúp phòng khám RHM vận hành trơn tru và sinh lời mỗi ngày, bạn bắt buộc phải tuân thủ 5 nguyên tắc thiết kế bất di bất dịch dưới đây.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ba914cf-ae37-483b-8690-43476d538070','070ab753-fe19-41c6-bd23-c8e5568519be',32,'text','Nếu thiếu đi các nguyên tắc này, bản đồ hành trình sẽ chỉ là một bức tranh trang trí, hoàn toàn mất kết nối với thực tế vận hành tại phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3b01d957-0e91-49ab-85fc-03c516c1d57b','15-customer-journey','070ab753-fe19-41c6-bd23-c8e5568519be',3,'Nguyên Tắc 1: Mỗi Tầng Phải Có Một Mục Tiêu Tối Thượng (Single Ultimate Goal)','nguyen-tac-1-moi-tang-phai-co-mot-muc-tieu-toi-thuong-single-ultimate-goal',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8be80e25-a86a-42da-a91f-b884f147f172','3b01d957-0e91-49ab-85fc-03c516c1d57b',33,'text','Sai lầm lớn nhất của các nhà quản trị là bắt một điểm chạm phải gánh vác quá nhiều nhiệm vụ. Bạn không thể vừa muốn khách hàng chú ý, vừa muốn họ tin tưởng rồi xuống tiền chốt lịch ngay trong một bài đăng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9eca55d6-cb01-47f1-8317-4fdf4bfef3f2','3b01d957-0e91-49ab-85fc-03c516c1d57b',34,'text','Tư duy đúng đắn của Dental Empire OS là: **Chia để trị**. Mỗi tầng trong hành trình phải được định vị một mục tiêu duy nhất, đóng vai trò là bệ phóng để đưa khách hàng bước sang tầng kế tiếp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb1e093a-d968-48a0-a023-0ebea7b23e97','3b01d957-0e91-49ab-85fc-03c516c1d57b',35,'text','- **Traffic (Lưu lượng):** Mục tiêu duy nhất là **Tạo sự chú ý**. Khiến người lạ dừng chân lại giữa hàng ngàn thông tin trên mạng xã hội.- **Trust (Niềm tin):** Mục tiêu là **Gieo định kiến tốt**. Giúp khách hàng nhận ra đây là một cơ sở y khoa uy tín, có tâm.- **Relationship (Mối quan hệ):** Mục tiêu là **Kích hoạt tương tác**. Biến người xem thầm lặng thành người sẵn sàng inbox chia sẻ nỗi đau răng miệng của họ.- **Authority Check (Kiểm chứng):** Mục tiêu là **Xóa bỏ hoài nghi**. Cho khách hàng tự kiểm tra năng lực chuyên môn của bác sĩ.- **Conversion (Chuyển đổi):** Mục tiêu là **Thúc đẩy hành động**. Chốt lịch hẹn và đưa khách hàng đến phòng khám.- **Patient Experience (Trải nghiệm):** Mục tiêu là **Tạo sự hài lòng tuyệt đối**. Khiến họ vượt qua nỗi sợ và thực sự cảm thấy *thích làm răng*.- **Referral (Lan tỏa):** Mục tiêu là **Biến khách cũ thành đại sứ**. Tự động sinh ra khách hàng mới từ sự hài lòng của khách hàng cũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b6ba537b-f8a2-409f-aa42-82fee42f30de','15-customer-journey','070ab753-fe19-41c6-bd23-c8e5568519be',3,'Nguyên Tắc 2: Không Đòi Hỏi Niềm Tin "Suông" Phải Có Tài Sản Hỗ Trợ (Asset-Backed Journey)','nguyen-tac-2-khong-oi-hoi-niem-tin-suong-phai-co-tai-san-ho-tro-asset-backed-jou',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1d3901a-eda3-47e8-ac02-1c61bfb658d3','b6ba537b-f8a2-409f-aa42-82fee42f30de',36,'text','**Mantra vận hành:** Bạn không thể yêu cầu bệnh nhân tin tưởng nếu bạn không chìa ra cho họ những bằng chứng không thể chối cãi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('920ee444-bba0-4122-a1b0-013c86916978','b6ba537b-f8a2-409f-aa42-82fee42f30de',37,'text','Tại mỗi nấc thang tâm lý, bạn phải chuẩn bị sẵn "vũ khí" tương ứng để trợ lực cho dòng chảy cảm xúc của khách hàng. Khách hàng đang ở tầng nào, hệ thống phải tự động hoặc chủ động hiển thị các **Trust Assets (Tài sản niềm tin)** của tầng đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a751838-b627-423a-a1e8-036834dc569f','b6ba537b-f8a2-409f-aa42-82fee42f30de',38,'text','- Khách muốn kiểm chứng chuyên môn? Phải có sẵn kho **Case thật**, bài phân tích bệnh lý và video Bác sĩ trưởng ca giải thích phác đồ.- Khách muốn biết trải nghiệm thực tế? Phải có hệ thống **Review 5 sao trên Google Maps**, video testimonial chân thực của người đi trước.- Khách muốn xác thực phòng khám có chuyên nghiệp không? Phải có một **Website chỉn chu**, hình ảnh cơ sở vật chất vô trùng công khai.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dfd39e43-9ac6-4128-abf3-8e605c940e6e','b6ba537b-f8a2-409f-aa42-82fee42f30de',39,'text','Hành trình khách hàng đi đến đâu, tài sản hỗ trợ phải được phủ sẵn đến đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9b16d953-89ce-4325-8c6c-4405ab84285f','15-customer-journey','070ab753-fe19-41c6-bd23-c8e5568519be',3,'Nguyên Tắc 3: Định Danh Người Chịu Trách Nhiệm (Clear Ownership)','nguyen-tac-3-inh-danh-nguoi-chiu-trach-nhiem-clear-ownership',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f2842c2-40da-4594-a787-2dc10208be15','9b16d953-89ce-4325-8c6c-4405ab84285f',40,'text','Một hành trình khách hàng bị đứt đoạn luôn bắt nguồn từ việc: **Cha chung không ai khóc.** Nếu bạn không gán trách nhiệm rõ ràng cho từng vị trí nhân sự tại mỗi điểm chạm, khách hàng sẽ rơi rụng một cách lãng phí. Trong hệ điều hành phòng khám bài bản, mỗi tầng phải có một "chủ sở hữu" (Owner) chịu trách nhiệm sinh tử:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('718c67ba-3534-4346-83f3-135e20950044','9b16d953-89ce-4325-8c6c-4405ab84285f',41,'text','- Tầng Traffic và Trust thuộc về **Đội ngũ Media/Marketing**.- Tầng Relationship và Conversion thuộc về **Đội ngũ Telesale / Chuyên viên tư vấn**.- Tầng Patient Experience thuộc về **Bác sĩ lâm sàng, Trợ thủ và Lễ tân**.- Tầng Review và Referral thuộc về **Bộ phận Chăm sóc khách hàng (Patient Care)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdd165c7-a92f-4020-96f7-6bfba7d8f378','9b16d953-89ce-4325-8c6c-4405ab84285f',42,'text','Khi một chỉ số ở tầng nào đi xuống, bạn biết chính xác mình cần ngồi lại với ai để tìm giải pháp tối ưu, không có chỗ cho sự đổ lỗi vòng quanh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ae17a27a-99c1-4da2-87f1-3f717e08f83f','15-customer-journey','070ab753-fe19-41c6-bd23-c8e5568519be',3,'Nguyên Tắc 4: Số Hóa Hành Trình - Đo Lường Được Mới Tối Ưu Được (Data-Driven Journey)','nguyen-tac-4-so-hoa-hanh-trinh-o-luong-uoc-moi-toi-uu-uoc-data-driven-journey',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54063357-a375-4ae0-aa67-c5597a47d35d','ae17a27a-99c1-4da2-87f1-3f717e08f83f',43,'text','**Nguyên lý cốt lõi:** Những gì không đo lường được thì không thể cải tiến được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4517da3-10e9-4060-8c03-3a10cc9b1d21','ae17a27a-99c1-4da2-87f1-3f717e08f83f',44,'text','Thay vì quản trị bằng cảm giác theo kiểu *"Tháng này hình như phòng khám vắng khách hơn"*, bạn phải số hóa toàn bộ hành trình bằng hệ thống KPI chi tiết cho từng chặng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0b30049-61be-44c2-a21e-952534dee4f1','ae17a27a-99c1-4da2-87f1-3f717e08f83f',45,'text','- Đội Marketing mang về bao nhiêu lượt hiển thị (CPM), bao nhiêu lượt click (CTR)?- Đội Sales đạt tỷ lệ đặt lịch (Booking Rate) là bao nhiêu %, tỷ lệ khách thực tế đến phòng khám (Show-up Rate) có đạt chuẩn không?- Đội Lâm sàng chốt phác đồ điều trị đạt bao nhiêu %?- Bộ phận CSKH mang về bao nhiêu Review mới và tỷ lệ giới thiệu (Referral Rate) là bao nhiêu?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d675990-b518-4fe6-b64a-0de2e8fc82ac','ae17a27a-99c1-4da2-87f1-3f717e08f83f',46,'text','Chính những con số cấu thành này sẽ chỉ ra chính xác "sức khỏe" của cỗ máy tăng trưởng đang gặp vấn đề ở phân khúc nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('847faddd-25e7-4ae7-88ed-f29fb8721b85','15-customer-journey','070ab753-fe19-41c6-bd23-c8e5568519be',3,'Nguyên Tắc 5: Customer Journey Phải Nối Liền Với Pipeline CRM (CRM Integration)','nguyen-tac-5-customer-journey-phai-noi-lien-voi-pipeline-crm-crm-integration',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ccde56ee-1777-4092-9b61-a266a4518f22','847faddd-25e7-4ae7-88ed-f29fb8721b85',47,'text','Bản đồ hành trình khách hàng chính là linh hồn, còn CRM chính là thể xác. Bản đồ chỉ thực sự sống khi nó được lập trình đồng bộ hoàn toàn vào đường ống (Pipeline) của hệ thống CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c0f6f5f5-9b4f-4c22-ae50-fc5c59d80934','847faddd-25e7-4ae7-88ed-f29fb8721b85',48,'text','Mỗi một bước đi của bệnh nhân ngoài thực tế phải tương ứng với một sự thay đổi trạng thái (Status) tự động trên màn hình quản trị. Khách hàng vừa điền form? CRM báo trạng thái **New Lead**. Khách đồng ý hẹn lịch? CRM nhảy sang trạng thái **Booked**. Khách điều trị xong? CRM chuyển về **Completed** và tự động kích hoạt lệnh gửi tin nhắn xin review.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76329482-bea1-4cc3-93c2-c3226051a5a2','847faddd-25e7-4ae7-88ed-f29fb8721b85',49,'text','Sự kết nối chặt chẽ này đảm bảo dữ liệu luôn thời gian thực, giúp nhà quản trị kiểm soát phòng khám từ xa một cách chính xác tuyệt đối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff6c5c34-08f7-4305-affa-1c345816732c','847faddd-25e7-4ae7-88ed-f29fb8721b85',50,'text','**Tóm lại:** Nằm lòng và áp dụng 5 nguyên tắc này khi thiết kế Customer Journey sẽ giúp phòng khám của bạn xây dựng được một quy trình vận hành nhất quán, không tỳ vết. Khách hàng đi vào hệ thống như đi trên một băng chuyền tự động mượt mà, an tâm và hạnh phúc mang lại sự tăng trưởng vượt bậc cho doanh nghiệp nha khoa của bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7b165f0a-9f9a-4c17-8515-0562d96d9dd3','15-customer-journey',NULL,2,'15.6 Cấu trúc 6 tầng của Customer Journey','156-cau-truc-6-tang-cua-customer-journey',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06533d74-8587-4faf-8cbd-89d0df0616cc','7b165f0a-9f9a-4c17-8515-0562d96d9dd3',51,'image',NULL,'book/15-customer-journey/d56c6b25-55d0-4295-bada-0a1ad3ac8ec1-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fbe05919-0e87-46dc-9845-82ce117e9c4d','15-customer-journey','7b165f0a-9f9a-4c17-8515-0562d96d9dd3',3,'Tầng 1: TRAFFIC - Mở khóa dòng chảy và đánh thức sự chú ý','tang-1-traffic-mo-khoa-dong-chay-va-anh-thuc-su-chu-y',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b54ea6d3-50ae-4c98-b1da-6ba4e7569a0c','fbe05919-0e87-46dc-9845-82ce117e9c4d',52,'text','Trong kiến trúc của cỗ máy Growth Engine, **Traffic (Lưu lượng truy cập)** chính là tầng cửa ngõ nơi đầu tiên mà một người lạ hoàn toàn lần đầu nhìn thấy, lướt qua hoặc biết đến sự tồn tại của phòng khám RHM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5fe8fb98-e80b-4b37-8b5a-825d6fc118a3','fbe05919-0e87-46dc-9845-82ce117e9c4d',53,'text','Tôi luôn nhắc nhở đội ngũ Media của mình một nguyên lý xương máu: **Mục tiêu của tầng này tuyệt đối không phải là chốt lịch hẹn ngay lập tức.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c7d62eb-78a3-4c3a-b9bc-d1bf994d0b87','fbe05919-0e87-46dc-9845-82ce117e9c4d',54,'text','Nha khoa là ngành kinh doanh dựa trên niềm tin cao độ và sự can thiệp trực tiếp vào cơ thể. Việc ép một người vừa xem video của bạn lần đầu phải inbox đặt lịch khám ngay là một sự vội vã sai lầm. Nhiệm vụ tối thượng của Traffic chỉ gói gọn trong hai chữ: **Chú ý**. Chúng ta cần đánh thức sự chú ý của họ, khơi gợi nỗi đau thầm kín và kéo họ bước chân vào hệ sinh thái nội dung của phòng khám để chuẩn bị cho các bước chuyển hóa tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('95980fb0-3137-4fd6-a86a-cb5836660cae','15-customer-journey','fbe05919-0e87-46dc-9845-82ce117e9c4d',4,'Góc Nhìn Tâm Lý: Bệnh Nhân Đang Nghĩ Gì Ở Tầng Traffic?','goc-nhin-tam-ly-benh-nhan-ang-nghi-gi-o-tang-traffic',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d93ed07b-d515-42bb-ba8c-9d5b5737e594','95980fb0-3137-4fd6-a86a-cb5836660cae',55,'text','Khách hàng ở giai đoạn này là những người lướt màn hình vô định. Họ chưa có nhu cầu cấp bách, chưa có niềm tin vào bạn, nhưng họ có những vấn đề răng miệng âm thầm. Một nội dung chạm đúng tầng Traffic sẽ kích hoạt những suy nghĩ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2edf00f4-57d1-46a0-a633-264a94a9ce97','95980fb0-3137-4fd6-a86a-cb5836660cae',56,'text','- *"Ơ, cái video ngắn này nói đúng tình trạng răng của mình thế nhỉ?"*- *"Hóa ra đánh răng bị chảy máu không đơn giản như mình nghĩ."*- *"Bác sĩ này giải thích nghe cuốn và dễ hiểu ghẽ."*- *"Phòng khám này nhìn sạch sẽ, có vẻ đáng chú ý đấy."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13f0445d-b2ab-42a6-ae6a-d09131f6ff89','95980fb0-3137-4fd6-a86a-cb5836660cae',57,'text','Họ có thể chưa bấm theo dõi ngay, chưa nhắn tin hỏi giá, nhưng hạt mầm nhận biết đã được gieo vào tâm trí của họ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b9416e46-1e31-470d-9941-e0131b7a15f9','15-customer-journey','fbe05919-0e87-46dc-9845-82ce117e9c4d',4,'Ma Trận Kênh Và Công Thức Nội Dung Chạm','ma-tran-kenh-va-cong-thuc-noi-dung-cham',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddc43553-efa9-426c-996f-2fb18c28e20b','b9416e46-1e31-470d-9941-e0131b7a15f9',58,'text','Để tiếp cận được lượng lớn tệp khách hàng tiềm năng một cách tự nhiên và nhanh chóng, hệ thống phòng khám cần làm chủ các định dạng ngắn (Short-form video) trên các nền tảng phân phối bằng thuật toán:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25547872-3739-4e10-b4fd-eb8beea2613b','b9416e46-1e31-470d-9941-e0131b7a15f9',59,'text','- **Các kênh chủ lực:** TikTok, Facebook Reels, YouTube Shorts, Zalo Video kết hợp cùng các chiến dịch Ads Video (chạy định dạng hiển thị tiếp cận rộng).- **Các nhóm nội dung "đánh trúng" tâm lý:***Video ngắn giải thích vấn đề:* Biến kiến thức nha khoa khô khan thành mẹo vặt đời sống.- *Nội dung Myth-busting (Giải mã hiểu lầm):* Ví dụ: *"Tẩy trắng răng có làm mòn men răng không?"*.- *Case Before/After siêu ngắn:* Tập trung vào sự biến đổi ngoạn mục về mặt thẩm mỹ để kích thích thị giác trong 3 giây đầu.- *Sai lầm thường gặp & Dấu hiệu cảnh báo:* *"3 dấu hiệu cảnh báo chiếc răng khôn của bạn đang phá hủy răng bên cạnh"*.- *Hỏi nhanh đáp gọn cùng Bác sĩ:* Tăng sự tương tác, thể hiện phong thái chuyên gia gần gũi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ac7b88be-1acd-4366-a93d-6f8f9a407664','15-customer-journey','fbe05919-0e87-46dc-9845-82ce117e9c4d',4,'Bộ Tài Sản Bắt Buộc Và Quy Trình Vận Hành Tinh Gọn','bo-tai-san-bat-buoc-va-quy-trinh-van-hanh-tinh-gon',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b67448f2-e4ad-47c2-a806-422c7d7b9f85','ac7b88be-1acd-4366-a93d-6f8f9a407664',60,'text','Traffic không đến từ sự ngẫu hứng. Để dòng chảy này luôn dồi dào, phòng khám phải chuẩn hóa kho tài sản nội dung và tuân thủ quy trình sản xuất nghiêm ngặt:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('111bb65f-7dae-4e17-adf0-5a88b1e741b8','ac7b88be-1acd-4366-a93d-6f8f9a407664',61,'text','**Kho tài sản cần có (Traffic Assets)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ffff9d7-49ab-40fa-94c9-f21b941de212','ac7b88be-1acd-4366-a93d-6f8f9a407664',62,'text','- **Content Pillar (Khung nội dung xương sống):** Định hướng rõ các chủ đề cốt lõi, không làm tràn lan.- **Hook Library (Thư viện mở đầu thu hút):** Bộ công thức giật tít, mở đầu video trong 3 giây đầu tiên để giữ chân người xem không lướt qua.- **Visual Guideline:** Bộ nhận diện hình ảnh, màu sắc, font chữ đồng bộ cho toàn bộ video của phòng khám để tạo sự ghi nhớ thương hiệu.- **Brand Intro/Outro ngắn:** Bộ nhận diện thương hiệu 1-2 giây tinh tế.- **Soft CTA (Lời kêu gọi nhẹ nhàng):** Không ép đặt lịch, chỉ khuyến khích: *Follow kênh, Inbox để nhận cẩm nang, Lưu lại video khi cần...*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cb43a447-799b-4515-8108-8426b2d3cfac','15-customer-journey','fbe05919-0e87-46dc-9845-82ce117e9c4d',4,'Quy trình xử lý dòng chảy Traffic','quy-trinh-xu-ly-dong-chay-traffic',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b285dd36-b433-40b5-a1df-5e9b53fc461d','cb43a447-799b-4515-8108-8426b2d3cfac',63,'image',NULL,'book/15-customer-journey/e7abbb9d-0982-4b78-bc0e-81794fe0242e-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('597809da-8b35-4748-a0cb-644512807627','15-customer-journey','fbe05919-0e87-46dc-9845-82ce117e9c4d',4,'Quản Trị Nhân Sự Và Hệ Thống Chỉ Số Đo Lường (KPIs)','quan-tri-nhan-su-va-he-thong-chi-so-o-luong-kpis',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0113eaed-e105-419a-a94f-6d16771be539','597809da-8b35-4748-a0cb-644512807627',64,'text','- **Nhân sự chịu trách nhiệm chính:** Khối **Marketing OS** (Chịu trách nhiệm về số lượng và chất lượng dòng traffic).- **Nhân sự phối hợp:** Founder/Bác sĩ trưởng ca (Cung cấp chuyên môn), Editor (Hậu kỳ), Ads Specialist (Cấu hình quảng cáo).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7cb3d56f-0f3e-4e14-baef-822aa96f59a3','597809da-8b35-4748-a0cb-644512807627',65,'image',NULL,'book/15-customer-journey/ac8b8f53-1089-4fb0-b3c6-bba296eda22c-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81678823-a1b3-4627-88f1-d9f0bed93b93','597809da-8b35-4748-a0cb-644512807627',66,'text','Để biết tầng Traffic của phòng khám có đang khỏe mạnh hay không, nhà quản lý không nhìn vào doanh thu ở giai đoạn này, mà phải kiểm soát các chỉ số đo lường hiệu suất (KPIs) sau trên Dashboard:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82d266a8-5805-4a01-b298-967d204fd190','597809da-8b35-4748-a0cb-644512807627',67,'text','- **Reach & Video Views:** Tổng lượng tiếp cận và số lượt xem video.- **Watch Time & Completion Rate (Tỷ lệ xem hết video):** Thước đo chính xác nhất đánh giá chất lượng nội dung. Nếu tỷ lệ xem hết dưới **20%**, kịch bản đang bị nhàm chán.- **Engagement Rate:** Tỷ lệ like, comment, share, lưu video.- **Profile Visits & Clicks:** Số lượng người tò mò bấm vào trang cá nhân hoặc đường link website của phòng khám.- **Cost per View / Cost per Engagement:** Chi phí tối ưu cho mỗi lượt xem và tương tác khi có sự can **thiệp của Ads.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('aa962eb5-924d-4fb6-8cd8-f496edf457fe','15-customer-journey','fbe05919-0e87-46dc-9845-82ce117e9c4d',4,'Những Cạm Bẫy Chết Người Cần Tránh Ở Tầng Traffic','nhung-cam-bay-chet-nguoi-can-tranh-o-tang-traffic',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04b8eb49-8173-41d5-8e53-6f0e4ca103ac','aa962eb5-924d-4fb6-8cd8-f496edf457fe',68,'text','Rất nhiều phòng khám hào hứng khoe những video đạt triệu view trên TikTok nhưng cuối cùng vẫn vắng khách. Đó là hậu quả của việc dính phải các lỗi tư duy kinh điển:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('215e4705-6fb4-4994-a5e3-e32bf312a968','aa962eb5-924d-4fb6-8cd8-f496edf457fe',69,'text','- **Bẫy Viral không liên quan:** Làm các nội dung nhảy nhót, hài nhảm để lấy view khủng nhưng tệp người xem lại là học sinh, sinh viên không đúng phân khúc khách hàng mục tiêu của các dịch vụ cao cấp (Implant, răng sứ).- **Thiếu Lời kêu gọi hành động (CTA) tinh tế:** Xem xong video rất hay nhưng bệnh nhân không biết phải làm gì tiếp theo, thế là họ lướt qua và quên mất bạn.- **Đứt gãy hành trình (Không dẫn sang tầng Trust):** Kéo khách vào xem video nhưng khi họ bấm vào hồ sơ hoặc trang cá nhân thì thông tin trống trỗng, không có địa chỉ, không có website, không có bằng chứng năng lực bác sĩ.- **Bỏ phí tệp Retargeting:** Sai lầm lớn nhất của Ads Specialist là không gom tệp những người đã xem video trên 25% hoặc 50% thời lượng để chạy quảng cáo bám đuổi (Remarketing) ở tầng sau. Bạn đang ném tiền qua cửa sổ nếu bỏ qua tệp khách hàng "đã chớm ấm" này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('39a5a729-4e79-48fa-a70e-7983a1cca24e','15-customer-journey','7b165f0a-9f9a-4c17-8515-0562d96d9dd3',3,'Tầng 2: TRUST - Xây dựng pháo đài niềm tin và định vị chuyên gia','tang-2-trust-xay-dung-phao-ai-niem-tin-va-inh-vi-chuyen-gia',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('965216e4-0193-49b0-88a3-a2e2bb4e2793','39a5a729-4e79-48fa-a70e-7983a1cca24e',70,'text','Nếu tầng Traffic là việc chúng ta ném một viên đá xuống mặt hồ để tạo ra những gợn sóng chú ý, thì **Tầng 2 - Trust (Niềm tin)** chính là lúc chúng ta giữ chân làn sóng đó lại, biến những người tò mò lướt qua thành những người thực sự dừng lại để lắng nghe.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4dbd2564-4a17-47b2-92c0-dc1f70b1eb1a','39a5a729-4e79-48fa-a70e-7983a1cca24e',71,'text','Trong ngành nha khoa, sự chú ý có thể mua được bằng tiền (chạy Ads đu trend, làm clip hài nhảm), nhưng niềm tin thì tuyệt đối không. Sau khi bệnh nhân biết đến phòng khám RHM của bạn, họ sẽ lập tức bật chế độ phòng thủ và hoài nghi. Tầng Trust sinh ra để giúp họ tự kiểm chứng, đánh giá và tự trả lời cho câu hỏi: *"Nơi này có đủ tầm, đủ tâm để mình giao phó nụ cười hay không?"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d3c682b-a51e-4d83-8917-e2ecece4c868','39a5a729-4e79-48fa-a70e-7983a1cca24e',72,'text','Chỉ khi pháo đài niềm tin này được xây dựng vững chắc, bệnh nhân mới sẵn sàng gạt bỏ nỗi sợ hãi để bước sang giai đoạn tương tác sâu hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a4dcb27f-b11a-48c2-8078-6719a727bca6','15-customer-journey','39a5a729-4e79-48fa-a70e-7983a1cca24e',4,'Góc Nhìn Tâm Lý: Cuộc Khảo Sát Ngầm Trong Tâm Trí Bệnh Nhân','goc-nhin-tam-ly-cuoc-khao-sat-ngam-trong-tam-tri-benh-nhan',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96ea32dd-f4e1-465b-84d8-f6676e42c1f7','a4dcb27f-b11a-48c2-8078-6719a727bca6',73,'text','Khách hàng ở tầng Trust không còn là người xa lạ lướt qua nữa. Họ đã chớm ấm. Họ đang có một vấn đề đau nhức hoặc một khao khát thẩm mỹ cần giải quyết, và họ đang âm thầm "soi" bạn rất kỹ với hàng loạt câu hỏi cân não:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86dc6660-5c83-4c63-9ce6-b3d5598bbb77','a4dcb27f-b11a-48c2-8078-6719a727bca6',74,'text','- *"Bác sĩ này nói nghe hay đấy, nhưng liệu có thực sự hiểu bản chất vấn đề răng miệng của mình không?"*- *"Phòng khám này có giấy phép, uy tín rõ ràng không hay chỉ là quảng cáo thổi phồng?"*- *"Đã có ai có tình trạng răng khấp khểnh/mất răng giống mình mà điều trị thành công ở đây chưa?"*- *"Giữa một rừng nha khoa ngoài kia, tại sao mình phải tin vị bác sĩ này?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('201679f1-ea64-4b82-b0c8-5a1fcc419d51','a4dcb27f-b11a-48c2-8078-6719a727bca6',75,'text','Nếu bạn không chuẩn bị sẵn câu trả lời thỏa đáng cho những câu hỏi này, bạn sẽ đánh rơi khách hàng ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f41c638f-1d88-4713-bd2c-c0b134e11d33','15-customer-journey','39a5a729-4e79-48fa-a70e-7983a1cca24e',4,'Hệ Thống Kênh Chủ Lực &amp; Ma Trận Nội Dung Giáo Dục Chuyên Sâu','he-thong-kenh-chu-luc-amp-ma-tran-noi-dung-giao-duc-chuyen-sau',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7acfd9a8-de90-4378-af3b-ef1c05550df6','f41c638f-1d88-4713-bd2c-c0b134e11d33',76,'text','Để xây dựng niềm tin vững chãi, chúng ta không thể dùng các video ngắn 15 giây hời hợt. Tầng này đòi hỏi những định dạng nội dung có chiều sâu, mang tính giáo dục cao và thể hiện rõ nét phong thái chuyên gia:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2561e95-2777-4238-b45b-3db6137deb68','f41c638f-1d88-4713-bd2c-c0b134e11d33',77,'text','- **Các kênh phân phối cốt lõi:** Facebook Page (nơi lưu trữ bài viết dài), Facebook cá nhân của Bác sĩ/Founder (tạo sự liên kết con người), YouTube (cho các video phân tích dài), hệ thống Livestream tương tác thực và Website chứa các bài viết chuyên môn sâu.- **Ma trận nội dung "Xây móng niềm tin":***Video giải thích chuyên sâu:* Phân tích cặn kẽ nguyên nhân, cơ chế sinh học của từng bệnh lý bằng ngôn từ bình dân.- *Livestream hỏi đáp trực tiếp:* Bác sĩ trực tiếp lên sóng giải quyết nỗi sợ của bệnh nhân theo thời gian thực. Sự chân thật không cắt ghép trên livestream là liều thuốc bổ cho niềm tin.- *Case Study lâm sàng (Before/After chuẩn hóa):* Không chỉ đưa ảnh, bác sĩ phải trực tiếp lồng tiếng (voice-over) để phân tích phác đồ: *"Tại sao ca này tôi chọn niềng răng không nhổ răng", "Tại sao ca implant này phải ghép xương"...*- *Chứng chỉ & Quan điểm điều trị:* Công khai năng lực y khoa của đội ngũ kết hợp với triết lý điều trị bảo tồn, trung thực.- *So sánh các phương án:* Phân tích khách quan ưu nhược điểm của từng giải pháp (ví dụ: *Cầu răng sứ vs. Cấy ghép Implant*) để khách hàng tự đưa ra lựa chọn thông minh nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3c079ee0-053d-4dbc-9a64-5a1b3446636b','15-customer-journey','39a5a729-4e79-48fa-a70e-7983a1cca24e',4,'Kho Tài Sản Trust &amp; Pipeline Nurturing','kho-tai-san-trust-amp-pipeline-nurturing',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0e1b306-27bc-444a-888d-f27c7d90eef1','3c079ee0-053d-4dbc-9a64-5a1b3446636b',78,'text','Niềm tin cần được tích lũy và đóng gói thành các module tài sản số để có thể tái sử dụng và phân phối tự động thông qua hệ thống Growth Engine:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49c4f63d-55f4-4959-b2e6-8ed4f925d5a8','3c079ee0-053d-4dbc-9a64-5a1b3446636b',79,'text','Kho tài sản Trust Assets cần quản trị',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0fac0b38-dff3-4d7c-884f-e308b653278e','3c079ee0-053d-4dbc-9a64-5a1b3446636b',80,'text','- **Doctor Profile (Hồ sơ Bác sĩ):** Được đóng gói chuyên nghiệp, ghi rõ bằng cấp, chứng chỉ chính quy và kinh nghiệm thực chiến.- **Case Library & Review Library:** Kho lưu trữ hàng trăm ca lâm sàng thành công và đánh giá 5 sao được phân loại khoa học theo từng dịch vụ để Sales tiện trích xuất.- **Livestream Library:** Tuyển tập những buổi tư vấn trực tuyến chất lượng cao.- **Long-form Content & FAQ:** Bộ tài liệu giải đáp tất cả các thắc mắc y khoa kinh điển từ A-Z.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eea3d4c4-cc5b-438e-9ef1-3a5d4a5619f7','15-customer-journey','39a5a729-4e79-48fa-a70e-7983a1cca24e',4,'Quy trình xử lý dòng chảy nuôi dưỡng niềm tin','quy-trinh-xu-ly-dong-chay-nuoi-duong-niem-tin',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b066edc-e008-47a4-b9df-4fbfc0f77f4e','eea3d4c4-cc5b-438e-9ef1-3a5d4a5619f7',81,'image',NULL,'book/15-customer-journey/61f7bda6-2cdc-464b-84fc-1d715a59083b-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bf77a21c-65cb-45b8-9a52-2e70a762f0c4','15-customer-journey','39a5a729-4e79-48fa-a70e-7983a1cca24e',4,'Phân Quyền Nhân Sự Và Bộ KPI Đo Lường Chất Lượng Niềm Tin','phan-quyen-nhan-su-va-bo-kpi-o-luong-chat-luong-niem-tin',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a43605a4-d98e-4dff-9101-26f578b94e69','bf77a21c-65cb-45b8-9a52-2e70a762f0c4',82,'text','- **Nhân sự chịu trách nhiệm chính:** Khối **Marketing OS** (Chịu trách nhiệm thiết kế phễu nội dung và kịch bản phân phối).- **Nhân sự phối hợp chặt chẽ:** Founder/Bác sĩ (Linh hồn chuyên môn, trực tiếp sản xuất nội dung gốc), Bộ phận CSKH (Lắng nghe phản hồi để tối ưu FAQ) và **Data OS** (Theo dõi hành vi dịch chuyển của tệp đối tượng).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7642a780-f4f8-44b1-9a92-3cfe09b5502a','bf77a21c-65cb-45b8-9a52-2e70a762f0c4',83,'image',NULL,'book/15-customer-journey/7f499034-c886-4f2a-a6a2-9f0f0a7f7b08-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a7334df-4579-4ffd-98e3-292407082fa5','bf77a21c-65cb-45b8-9a52-2e70a762f0c4',84,'text','Để đo lường xem khách hàng có thực sự tin tưởng phòng khám hay không, hãy nhìn vào các chỉ số thiên về **chất lượng tương tác** thay vì số lượng view bề nổi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f87c4d62-0ac2-438d-afdc-0cb70be71697','bf77a21c-65cb-45b8-9a52-2e70a762f0c4',85,'text','- **Watch Time (Thời gian xem):** Khách hàng chịu ngồi xem video của bạn càng lâu, độ thấm niềm tin càng cao.- **Engagement Quality:** Các bình luận không còn là "chấm", "inbox giá" hời hợt, mà là những câu hỏi mô tả chi tiết tình trạng bệnh lý của họ.- **Save & Share Rate:** Tỷ lệ lưu lại và chia sẻ bài viết kiến thức của phòng khám.- **Livestream Attendance:** Số lượng người xem duy trì ổn định xuyên suốt buổi livestream của bác sĩ.- **Retargeting CTR (Tỷ lệ nhấp bám đuổi):** Đo lường mức độ hiệu quả khi dùng Ads nhắc lại các Case thật trước tệp khách hàng cũ.- **Lead từ Trust Content:** Số lượng Lead chất lượng cao tự nguyện inbox sau khi đọc/xem các bài viết chuyên sâu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ebd26003-d232-43ba-84ae-0b1670fbe0c2','15-customer-journey','39a5a729-4e79-48fa-a70e-7983a1cca24e',4,'Những Lỗi Chí Mạng Biến Tầng Trust Thành "Bãi Hoang"','nhung-loi-chi-mang-bien-tang-trust-thanh-bai-hoang',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ba8295d-afff-4412-b56e-ba79138a45a8','ebd26003-d232-43ba-84ae-0b1670fbe0c2',86,'text','Không ít phòng khám đổ hàng trăm triệu chạy quảng cáo kéo traffic về trang, nhưng tỷ lệ chuyển đổi sang nhắn tin vẫn bằng không. Lý do nằm ở những lỗ hổng chết người sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0598f82-028d-4efc-b2d3-639b5c164421','ebd26003-d232-43ba-84ae-0b1670fbe0c2',87,'text','- **Bẫy "Chăm chăm bán hàng":** Fanpage hoặc kênh truyền thông tràn ngập các bài viết giật tít, ép khách xuống tiền, xả kho ưu đãi... mà hoàn toàn thiếu vắng các nội dung giáo dục, chia sẻ kiến thức. Khách hàng sẽ cảm thấy đây là một "thương hội" chứ không phải một cơ sở y tế.- **Cơ sở "Vô diện" (Missing Doctor):** Trốn sau những tấm ảnh mạng, hình thiết kế đồ họa lung linh nhưng tuyệt đối không thấy gương mặt, giọng nói của Bác sĩ điều trị. Người ta chỉ tin con người, không tin logo hay những bức tường vô tri.- **Nghèo nàn bằng chứng thực tế:** Thiếu hụt nghiêm trọng hệ thống Case thật và Review thật từ những con người bằng xương bằng thịt. Mọi lời nói của bạn đều trở thành vô nghĩa nếu thiếu đi Social Proof.- **Bỏ quên nỗi sợ của bệnh nhân:** Nội dung quá vĩ mô về máy móc triệu đô nhưng bỏ quên việc giải tỏa những nỗi lo thực tế, sát sườn của người bệnh: *sợ đau, sợ biến chứng, sợ bị lừa.*- **Đứt xích vận hành:** Nội dung Trust làm rất hay, khách hàng comment hỏi han rất sâu nhưng hệ thống lại không có cơ chế tự động hoặc thủ công để điều hướng họ vào Inbox/Zalo nhằm chăm sóc và chốt lịch hẹn (Booking). Bạn đang tự tay dâng khách hàng của mình cho những đối thủ săn đón nhiệt tình hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8d490637-893a-41f7-9d3d-71f463936642','15-customer-journey','7b165f0a-9f9a-4c17-8515-0562d96d9dd3',3,'Tầng 3: Relationship - Mối quan hệ và nghệ thuật khai thác nỗi đau bệnh nhân','tang-3-relationship-moi-quan-he-va-nghe-thuat-khai-thac-noi-au-benh-nhan',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6752f3fd-69ee-41a4-9eae-f74b163722d0','8d490637-893a-41f7-9d3d-71f463936642',88,'text','Nếu tầng Traffic và Trust là những hoạt động truyền thông một chiều nơi phòng khám phát đi thông điệp và bệnh nhân âm thầm quan sát thì **Tầng 3 - Relationship (Mối quan hệ)** chính là khoảnh khắc phá vỡ tảng băng im lặng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1ddbad28-be2f-4eaf-8b40-92133b41b520','8d490637-893a-41f7-9d3d-71f463936642',89,'text','Đây là giai đoạn bước ngoặt khi một người xem vãng lai chính thức phát ra **tín hiệu có nhu cầu thực tế**. Họ chủ động để lại một bình luận, gửi một tin nhắn inbox qua Messenger, nhắn tin vào Zalo OA, điền vào form đăng ký trên Website hoặc trực tiếp bốc máy gọi vào số Hotline của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4fd348a-f0cf-48b4-b413-c729dd6c4838','8d490637-893a-41f7-9d3d-71f463936642',90,'text','Trong hệ điều hành Dental Empire OS, tôi luôn quán triệt với đội ngũ của mình: Khách hàng nhắn tin không phải để chúng ta "bán hàng", mà là để chúng ta **xây dựng một mối quan hệ**. Nếu bạn đối xử với một tin nhắn inbox như một đơn hàng thương mại điện tử thuần túy, bạn sẽ thất bại. Đây là nơi sự thấu cảm y khoa và nghệ thuật giao tiếp phải lên tiếng để biến một người đang tò mò thành một bệnh nhân sẵn sàng đặt lịch hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a8c0a451-4044-42cc-baa8-ad3c25951de9','15-customer-journey','8d490637-893a-41f7-9d3d-71f463936642',4,'Góc Nhìn Tâm Lý: Khách Hàng Đang "Thử Lòng" Phòng Khám Như Thế Nào?','goc-nhin-tam-ly-khach-hang-ang-thu-long-phong-kham-nhu-the-nao',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c0d3ef11-4404-4270-a359-d68b4fc134e8','a8c0a451-4044-42cc-baa8-ad3c25951de9',91,'text','Bệnh nhân khi chủ động liên hệ ở giai đoạn này thường mang một tâm lý vừa khao khát giải quyết vấn đề, lại vừa vô cùng đề phòng. Đằng sau những câu hỏi có vẻ hời hợt về giá cả, tâm trí họ thực chất đang tìm kiếm sự an toàn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1ea29a7-d7fb-4bcd-bb83-efe7ac636f82','a8c0a451-4044-42cc-baa8-ad3c25951de9',92,'text','- *"Răng mình bị hô/móm/sâu thế này không biết qua đây có chữa được dứt điểm không?"*- *"Chi phí niềng răng/implant ở đây khoảng bao nhiêu, có bị phát sinh hay bị ''vẽ'' thêm bệnh không?"*- *"Làm cái này có đau không? Mình sợ nhất là cảm giác ê buốt khi chạm vào răng."*- *"Liệu mình có đang nói chuyện với một robot tự động hay một chuyên viên thực sự hiểu biết?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c67f301-339d-4dfa-b00f-29b07328dc11','a8c0a451-4044-42cc-baa8-ad3c25951de9',93,'text','Họ muốn một giải pháp được cá nhân hóa cho riêng mình, chứ không phải một kịch bản sao chép hàng loạt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('10a59a4a-8d0d-46ba-9cd0-0c388053af5e','15-customer-journey','8d490637-893a-41f7-9d3d-71f463936642',4,'Hệ Thống Điểm Chạm Và Kịch Bản Phản Hồi Chạm Đến Cảm Xúc','he-thong-iem-cham-va-kich-ban-phan-hoi-cham-en-cam-xuc',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1d74da3-72ef-4481-9216-6824242c4526','10a59a4a-8d0d-46ba-9cd0-0c388053af5e',94,'text','Để quản trị tốt tầng Relationship, phòng khám cần quy hoạch toàn bộ các kênh giao tiếp đa nền tảng về một mối (Messenger, Zalo cá nhân, Zalo OA, Hotline, Website form) và chuẩn hóa nội dung phản hồi theo các bước:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('45d758a1-947b-4d88-a9b1-9364f61838f9','10a59a4a-8d0d-46ba-9cd0-0c388053af5e',95,'text','- **Chào hỏi cá nhân hóa:** Tuyệt đối không dùng các câu trả lời tự động lạnh lùng. Hãy chào bằng tên riêng và thể hiện sự sẵn sàng lắng nghe.- **Bộ câu hỏi phân loại (Qualification):** Thay vì vội vã báo giá, hãy đặt câu hỏi ngược lại để tìm hiểu nguyên nhân gốc rễ: *"Anh/chị bị tình trạng này lâu chưa?", "Trước đây mình đã từng điều trị ở đâu chưa ạ?"*.- **Tư vấn định hướng y khoa:** Đưa ra những nhận định sơ bộ mang tính chuyên môn cao nhưng bằng ngôn ngữ dễ hiểu nhất để xoa dịu nỗi lo của họ.- **Tận dụng Trust Assets đúng lúc:** Khách hỏi về dịch vụ nào, lập tức gửi **Case thật** và **Review** của bệnh nhân có tình trạng tương tự để chứng minh năng lực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2086154b-1c67-4f0f-95bd-0b19b2ec9ccb','15-customer-journey','8d490637-893a-41f7-9d3d-71f463936642',4,'Bộ "Vũ Khí" Tài Sản Và Quy Trình Xử Lý Lead Chuẩn SLA','bo-vu-khi-tai-san-va-quy-trinh-xu-ly-lead-chuan-sla',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3450dbc3-1ac5-45ad-a33b-ec644010d635','2086154b-1c67-4f0f-95bd-0b19b2ec9ccb',96,'text','Một mối quan hệ có thể chết yểu chỉ sau 10 phút nếu tốc độ phản hồi quá chậm hoặc câu trả lời cụt lủn. Phòng khám cần trang bị bộ tài sản thực chiến sau cho đội ngũ Sales/CSKH:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc19db9c-02e5-4b67-9353-f4f5f87359bf','2086154b-1c67-4f0f-95bd-0b19b2ec9ccb',97,'text','**Kho tài sản Relationship cần chuẩn hóa**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('627caf85-3d03-4842-8211-7da7821d9598','2086154b-1c67-4f0f-95bd-0b19b2ec9ccb',98,'text','- **Inbox & Call Script (Kịch bản Chat/Gọi điện):** Bộ kịch bản mẫu linh hoạt theo từng tình trạng bệnh lý (niềng răng, implant, thẩm mỹ).- **Lead Qualification Form:** Khung câu hỏi nhanh để phân loại khách hàng (Họ đang ở mức độ Nóng, Ấm hay Lạnh; ngân sách dự kiến bao nhiêu).- **FAQ Script:** Bộ câu trả lời chuẩn cho các câu hỏi kinh điển về giá cả, thời gian bảo hành, quy trình trả góp và nỗi sợ đau.- **Price Explanation Script:** Kịch bản giải thích cấu trúc giá, tập trung vào giá trị nhận được thay vì chỉ đưa ra một con số thô cứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f02172a0-bc3b-4da1-824f-337cf0dd00cd','15-customer-journey','8d490637-893a-41f7-9d3d-71f463936642',4,'Quy trình xử lý dữ liệu từ Điểm chạm đến CRM','quy-trinh-xu-ly-du-lieu-tu-iem-cham-en-crm',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d24409d3-79fc-4ce1-ab17-70978ed82b79','f02172a0-bc3b-4da1-824f-337cf0dd00cd',99,'image',NULL,'book/15-customer-journey/747e66ca-7e2e-4270-9f63-f04787cd68ea-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2a0c8849-16ea-40d2-9e5e-6ee07bc4ddce','15-customer-journey','8d490637-893a-41f7-9d3d-71f463936642',4,'Phân Quyền Nhân Sự Và Bộ Chỉ Số Đo Lường Relationship','phan-quyen-nhan-su-va-bo-chi-so-o-luong-relationship',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ffcf575e-4549-4e02-8845-2a780de8c865','2a0c8849-16ea-40d2-9e5e-6ee07bc4ddce',100,'text','- **Nhân sự chịu trách nhiệm chính:** Khối **Sales OS / CSKH** (Những người trực tiếp cầm máy, trực chat, chịu trách nhiệm về tỷ lệ chuyển đổi từ tin nhắn sang lịch hẹn).- **Nhân sự phối hợp:** Marketing OS (Tối ưu nguồn lead đổ về), Clinic OS (Hỗ trợ chuyên môn khi gặp ca khó) và Data OS (Đo lường các chỉ số vận hành).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bcdd5282-c815-4c54-8964-4f3ef7b4429a','2a0c8849-16ea-40d2-9e5e-6ee07bc4ddce',101,'image',NULL,'book/15-customer-journey/656d2c96-8d37-49f1-b397-647fdabb7793-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('334a7481-8f01-4855-b288-e4e1a74a6ee6','2a0c8849-16ea-40d2-9e5e-6ee07bc4ddce',102,'text','Hiệu suất của tầng Relationship được số hóa hoàn toàn qua các chỉ số cốt lõi trên Dashboard quản trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0169bad-f1ad-4e04-8835-c9891919fb09','2a0c8849-16ea-40d2-9e5e-6ee07bc4ddce',103,'text','- **Response Time (Thời gian phản hồi):** Tốc độ phản hồi tin nhắn đầu tiên. Tiêu chuẩn vàng của ngành nha khoa hiện tại là **dưới 5 phút**.- **Contact Rate (Tỷ lệ kết nối):** Đặc biệt quan trọng với lead từ form đăng ký—bao nhiêu % khách hàng thực sự nhấc máy khi gọi lại.- **Qualified Lead Rate:** Tỷ lệ lead đúng nhu cầu và đúng tệp khách hàng mục tiêu của phòng khám.- **Booking Offer Rate & Booking Rate:** Tỷ lệ nhân viên chủ động mời đặt lịch và tỷ lệ khách hàng gật đầu chốt ngày giờ qua khám thành công.- **Follow-up Completion Rate:** Tỷ lệ nhân viên tuân thủ kỷ luật gọi lại/nhắn tin lại cho các lead chưa chốt lịch theo đúng lịch hẹn của CRM.- **Lost Lead Reason:** Thống kê chi tiết lý do mất khách (do giá cao, do địa chỉ xa, do sợ đau...) để liên tục tối ưu lại kịch bản.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a8d695b-4be1-4e66-8bf5-301926df2383','15-customer-journey','8d490637-893a-41f7-9d3d-71f463936642',4,'Những Chiếc Bẫy Kinh Điển Khiến Khách Hàng "Lặng Lẽ Ra Đi"','nhung-chiec-bay-kinh-ien-khien-khach-hang-lang-le-ra-i',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d5714d1-58a6-45f3-a402-181ef58ff905','9a8d695b-4be1-4e66-8bf5-301926df2383',104,'text','Rất nhiều phòng khám đang tự tay "đốt tiền" của mình vì để đội ngũ tư vấn mắc phải những sai lầm chết người sau ở tầng Relationship:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('20bc2ffe-ee25-4cb9-af74-4b4c3fb13361','9a8d695b-4be1-4e66-8bf5-301926df2383',105,'text','- **Phản hồi rùa bò:** Khách nhắn tin từ 8h sáng nhưng tận 11h trưa mới có người trả lời. Ở thời đại số, sự chậm trễ này đồng nghĩa với việc bạn đã nhường khách cho đối thủ.- **Bẫy "Báo giá tuột quần":** Khách vừa hỏi *"Niềng răng bao nhiêu tiền em?"*, nhân viên lập tức thả một bảng giá dằng dặc kèm theo lời mời gọi giảm giá. Không khai thác nhu cầu, không xây dựng giá trị, khách hàng sẽ "đọc và không trả lời" vì họ chưa thấy lý do vì sao phải trả mức giá đó.- **Tư vấn cụt ngủn, thiếu tương tác:** Trả lời một cách thụ động, khách hỏi câu nào đáp câu nấy, tuyệt đối không đặt câu hỏi ngược lại để dẫn dắt cuộc hội thoại và khơi gợi nỗi đau của bệnh nhân.- **Thất lạc dữ liệu (Không lưu CRM):** Giao tiếp với khách hoàn toàn bằng chat tay ngẫu nhiên, không nhập hồ sơ vào CRM, dẫn đến việc người sau tiếp quản không biết người trước đã hứa hẹn những gì với khách.- **Bỏ quên khâu bám đuổi (No Follow-up):** Khách bảo *"Để chị suy nghĩ thêm"*, nhân viên im lặng luôn và không bao giờ nhắn tin hỏi thăm lại. Hãy nhớ, phần lớn doanh thu nha khoa nằm ở những cuộc gọi/tin nhắn chăm sóc lại lần thứ 2, thứ 3.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d539ab7-9ea6-45db-9302-b2bc36a26d03','9a8d695b-4be1-4e66-8bf5-301926df2383',106,'text','Giai đoạn Relationship là chặng đua của sự kiên nhẫn và lòng thấu cảm. Khi bạn làm tốt tầng này, bạn không chỉ mang về một lịch hẹn, mà bạn đã gieo vào lòng bệnh nhân một ấn tượng sâu sắc rằng: Đây là nơi thực sự quan tâm đến sức khỏe của họ, mở đường cho một trải nghiệm lâm sàng hoàn hảo tại phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('18f59ed1-5861-4ed8-bd98-500099de81f0','15-customer-journey','7b165f0a-9f9a-4c17-8515-0562d96d9dd3',3,'Tầng 4: Authority Check - Giai đoạn kiểm chứng uy tín và khảo sát ngầm.','tang-4-authority-check-giai-oan-kiem-chung-uy-tin-va-khao-sat-ngam',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78a04092-00f0-4c93-b460-ac08c4177a9d','18f59ed1-5861-4ed8-bd98-500099de81f0',107,'text','Sau khi bước qua giai đoạn thiết lập mối quan hệ ban đầu (Relationship), khi khách hàng đã phát đi tín hiệu quan tâm, họ sẽ không lập tức đặt lịch ngay. Trái lại, họ sẽ bước vào một giai đoạn phòng thủ tiếp theo, mang tính lý trí và cẩn trọng hơn rất nhiều: **Tầng 4 - Authority Check (Kiểm chứng uy tín)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9160e4e4-2791-4bbd-bda7-c644a6a81a5a','18f59ed1-5861-4ed8-bd98-500099de81f0',108,'text','Trong ngành nha khoa, nơi các dịch vụ can thiệp trực tiếp vào cơ thể, ảnh hưởng sâu sắc đến sức khỏe, diện mạo thẩm mỹ, đi kèm với mức chi phí không hề nhỏ thì bệnh nhân luôn có xu hướng thực hiện một cuộc "điều tra ngầm". Họ đóng vai trò là một thám tử tư để tự mình rà soát, đối chiếu mọi lời hứa quảng cáo của phòng khám RHM với thực tế hiển thị trên môi trường số.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('16c3b612-aeb7-45ef-b948-33090a491443','18f59ed1-5861-4ed8-bd98-500099de81f0',109,'text','Mục tiêu của tầng này là biến sự hoài nghi cuối cùng thành chiếc chìa khóa vạn năng mở cửa lòng tin, thúc đẩy họ dứt khoát đưa ra hành động chuyển đổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('16212897-ace0-438f-8295-91d032ef5fcc','15-customer-journey','18f59ed1-5861-4ed8-bd98-500099de81f0',4,'Góc Nhìn Tâm Lý: Bệnh Nhân Đang Sàng Lọc Bạn Bằng Thước Đo Nào?','goc-nhin-tam-ly-benh-nhan-ang-sang-loc-ban-bang-thuoc-o-nao',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d322e7a-f02c-498b-bddc-6efba2ff1b31','16212897-ace0-438f-8295-91d032ef5fcc',110,'text','Khách hàng ở tầng Authority Check không còn đọc lướt qua bài viết của bạn để giải trí. Họ đang cân nhắc ví tiền và sự an toàn của bản thân. Trong đầu họ sẽ liên tục chạy một bộ lọc khắt khe với 5 câu hỏi sinh tử:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a2e8f34-40a3-4bb9-b7c8-48fa7fedfd35','16212897-ace0-438f-8295-91d032ef5fcc',111,'text','- *"Phòng khám này có cơ sở thật, máy móc thật không, hay chỉ là một thương hiệu ảo trên mạng?"*- *"Những người từng làm răng ở đây khen thật hay là do phòng khám tự seeding, tự mua đánh giá?"*- *"Vị bác sĩ sẽ trực tiếp cắm implant/niềng răng cho mình là ai, bằng cấp thế nào, năng lực ra sao?"*- *"Đã có ca lâm sàng nào có tình trạng phức tạp và tệ như răng của mình mà họ chữa khỏi chưa?"*- *"Địa chỉ phòng khám nằm ở đâu, có thuận tiện giao thông và có chỗ đỗ xe đàng hoàng không?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6104b6a4-7762-4410-8f1d-609710417325','16212897-ace0-438f-8295-91d032ef5fcc',112,'text','Nếu hệ sinh thái số của bạn không tự động trả lời một cách hoàn hảo những câu hỏi này, toàn bộ chi phí marketing đổ vào các tầng trước sẽ lập tức tan thành mây khói.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2c803589-9fe1-4b45-88e5-b04188aec5be','15-customer-journey','18f59ed1-5861-4ed8-bd98-500099de81f0',4,'Hệ Thống Kênh Và Bộ Khung Nội Dung "Bảo Chứng" Chuyên Môn','he-thong-kenh-va-bo-khung-noi-dung-bao-chung-chuyen-mon',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c41594a6-5d7f-4b44-94a4-fe5afa89e4de','2c803589-9fe1-4b45-88e5-b04188aec5be',113,'text','Để vượt qua bài kiểm tra nghiêm ngặt này của bệnh nhân, phòng khám không thể dùng những lời hứa hẹn. Chúng ta phải phơi bày năng lực thực tế thông qua các kênh hạ tầng uy tín và kho tài sản niềm tin chuẩn hóa:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53e60819-dc58-45b9-be7a-c7ce5ef273d1','2c803589-9fe1-4b45-88e5-b04188aec5be',114,'text','- **Các kênh hạ tầng cốt lõi:** Google Maps (Google Business Profile), Hệ thống Website chính thức, Thư viện Case lâm sàng thực tế, Kho Video Testimonial chất lượng cao và Hồ sơ khoa học của đội ngũ Bác sĩ.- **Ma trận nội dung mang tính kiểm chứng:***Trang giới thiệu Bác sĩ:* Minh bạch bằng cấp, chứng chỉ hành nghề chính quy, chuyên khoa sâu và kinh nghiệm thực chiến.- *Trang dịch vụ chuyên sâu:* Mô tả rõ quy trình điều trị chuẩn y khoa, minh bạch các bước và các loại vật liệu sử dụng.- *Bằng chứng thép (Case Before/After & Video Feedback):* Những ca lâm sàng thành công được đóng gói chỉn chu, chân thực và không chỉnh sửa quá đà.- *Chính sách bảo hành và cam kết:* Các điều khoản bảo hành rõ ràng đối với răng sứ, implant, tạo sự an tâm tuyệt đối về mặt pháp lý cho bệnh nhân.- *Hình ảnh trang thiết bị:* Phô diễn phòng vô trùng trung tâm, hệ thống máy CT Cone Beam, máy quét dấu hàm... để chứng minh quy mô của Clinic System.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a4a88c2f-ab03-45c1-b5e8-a1e6b1e44025','15-customer-journey','18f59ed1-5861-4ed8-bd98-500099de81f0',4,'Quy Trình Vận Hành: Đường Ống Đưa Khách Qua Lớp Bộ Lọc Uy Tín','quy-trinh-van-hanh-uong-ong-ua-khach-qua-lop-bo-loc-uy-tin',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9932411d-1791-4c12-811f-ab9371d200a4','a4a88c2f-ab03-45c1-b5e8-a1e6b1e44025',115,'text','Hành trình kiểm chứng của khách hàng cần được định hướng một cách khéo léo bởi đội ngũ Sales dựa trên kho tài sản số có sẵn, thay vì để họ tự bơi giữa dòng thông tin hỗn loạn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0819a71-3bdf-4f55-9765-1f21ef12c63b','a4a88c2f-ab03-45c1-b5e8-a1e6b1e44025',116,'image',NULL,'book/15-customer-journey/1bd2ce84-7689-4c1c-9a1b-9511cb631340-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('71b5a4c7-c755-4926-a545-f17ee3768ae3','15-customer-journey','18f59ed1-5861-4ed8-bd98-500099de81f0',4,'Phân Quyền Nhân Sự Và Bộ Chỉ Số Đo Lường Sức Nặng Uy Tín','phan-quyen-nhan-su-va-bo-chi-so-o-luong-suc-nang-uy-tin',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('790db816-940d-4e4c-a8f7-4da3fcd0e616','71b5a4c7-c755-4926-a545-f17ee3768ae3',117,'text','- **Nhân sự chịu trách nhiệm chính:** Khối **Marketing OS** (Chịu trách nhiệm xây dựng, tối ưu giao diện Website, quản trị thứ hạng và hình ảnh trên Google Maps).- **Nhân sự phối hợp thực chiến:** Sales OS (Biết cách trích xuất tài sản gửi đúng lúc cho khách), Clinic OS & Patient OS (Cung cấp tư liệu y khoa chuẩn xác) và Referral OS (Đốc thúc thu thập review thật từ ghế răng để đẩy lên Google Maps).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('800b39a4-fa31-4ad3-b6c8-c82a44d17731','71b5a4c7-c755-4926-a545-f17ee3768ae3',118,'image',NULL,'book/15-customer-journey/04a7e169-c667-4e2d-88f6-0b504c1afebc-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d28d244-9f24-4c80-b412-8107ba597444','71b5a4c7-c755-4926-a545-f17ee3768ae3',119,'text','Sức mạnh của tầng Authority Check được đo lường cụ thể bằng các chỉ số hành vi thực tế của khách hàng trên Dashboard:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44bbbd69-1486-400c-9a09-f86572a036be','71b5a4c7-c755-4926-a545-f17ee3768ae3',120,'text','- **Google Maps Metrics:** Lượt tìm kiếm tên thương hiệu (Branded Search Volume), lượt xem bản đồ, số cuộc gọi trực tiếp từ Maps và số lượt bấm chỉ đường (Direction Requests).- **Website Performance:** Số lượt truy cập (Visits), thời gian ở lại trang (Time on page) và lượt xem trang Hồ sơ bác sĩ/Thư viện ca lâm sàng.- **Review Quality:** Tổng số lượng đánh giá trên Google Maps và Điểm sao trung bình (Yêu cầu giữ vững từ **4.7 đến 5.0**).- **Conversion Rate after Sent:** Tỷ lệ chuyển đổi thành lịch hẹn thành công ngay sau khi Sales gửi tài liệu kiểm chứng chuyên môn cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e7fa4e28-b934-4d6c-bc73-b00ffb69cd95','15-customer-journey','18f59ed1-5861-4ed8-bd98-500099de81f0',4,'Những Lỗ Hổng Chí Mạng Khiến Phòng Khám Bị "Đánh Trượt" Uy Tín','nhung-lo-hong-chi-mang-khien-phong-kham-bi-anh-truot-uy-tin',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd380458-1778-423d-bf1e-ee7b0defad73','e7fa4e28-b934-4d6c-bc73-b00ffb69cd95',121,'text','Rất nhiều phòng khám RHM làm nội dung thu hút rất tốt, nói chuyện với khách rất hay, nhưng khách cứ một đi không trở lại. Lý do là vì bạn đã để lộ những điểm yếu chết người khi khách tiến hành kiểm chứng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3bec13a9-ff7b-48d5-9ed7-936a0c4bf541','e7fa4e28-b934-4d6c-bc73-b00ffb69cd95',122,'text','- **Google Maps "vắng như chùa bà đanh":** Khách gõ tên phòng khám trên Google Maps chỉ thấy lèo tèo vài ba cái đánh giá, hoặc tệ hơn là không có lấy một lượt review nào. Sự thiếu vắng bằng chứng xã hội (Social Proof) này sẽ giết chết niềm tin ngay lập tức.- **Website sơ sài, thiếu chỉn chu:** Giao diện lỗi thời, bài viết cẩu thả, hình ảnh mờ nhạt, bảng giá mập mờ. Một ngôi nhà online nhếch nhác sẽ khiến khách hàng đánh giá thấp năng lực vận hành thực tế của phòng khám.- **"Vô diện" về mặt chuyên môn (No Doctor Profile):** Giấu nhẹm thông tin về bác sĩ điều trị. Khách hàng không biết ai sẽ là người cầm dao, cầm kìm can thiệp vào răng của mình, họ sẽ chọn một nơi minh bạch hơn.- **Kho Case thật nghèo nàn hoặc chưa chuẩn hóa:** Hình ảnh Before/After chụp lệch góc, thiếu ánh sáng, không có phân tích chuyên môn đi kèm, nhìn giống hình ảnh copy từ trên mạng hơn là ca thực tế tại phòng khám.- **Sales "tay không bắt giặc":** Sai lầm lớn nhất của đội ngũ Sales là khi khách hàng đưa ra lời từ chối hoặc hoài nghi về chuyên môn, nhân viên chỉ biết cam kết suông bằng miệng mà không biết dùng hệ thống link Website, video Testimonial hay link Google Maps để ném ra làm bằng chứng đập tan rào cản.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ceb6cbcb-01bd-4c5a-8c88-0f39196adecb','e7fa4e28-b934-4d6c-bc73-b00ffb69cd95',123,'text','Tầng Authority Check là chốt chặn cuối cùng kiểm tra bản lĩnh của một thương hiệu nha khoa thực chiến. Khi bạn chuẩn hóa được tầng này, bạn đang xây dựng một bệ phóng vững chắc, giúp bệnh nhân cởi bỏ hoàn toàn sự phòng thủ để hồ hởi bước vào giai đoạn đặt lịch và trải nghiệm dịch vụ điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d','15-customer-journey','7b165f0a-9f9a-4c17-8515-0562d96d9dd3',3,'Tầng 5: Search Layer - Đón đầu nhu cầu, chiếm lĩnh không gian tìm kiếm','tang-5-search-layer-on-au-nhu-cau-chiem-linh-khong-gian-tim-kiem',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('744017a6-1e85-482f-86ed-c8b9b3fc0302','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',124,'text','Nếu như mạng xã hội (Facebook, TikTok) là thế giới của sự "đánh chặn", nơi chúng ta tìm cách ngắt quãng hành vi giải trí của khách hàng bằng những nội dung thu hút thì **Tầng 5 - Search Layer (Lớp tìm kiếm chủ động)** lại là một chiến trường hoàn toàn khác. Đây là nơi phòng khám RHM tiếp cận những bệnh nhân có **Intent (Ý định) cao nhất**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('17a4d657-0fb9-4714-a979-2cf32efbae77','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',125,'text','Khách hàng ở tầng Search Layer không lướt màn hình vô định. Họ đang chủ động gõ từng dòng chữ để đi tìm giải pháp cho nỗi đau hoặc khao khát của chính mình. Họ có nhu cầu thực tế, có ngân sách chuẩn bị sẵn và mức độ sẵn sàng điều trị vượt trội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1512505f-e3b4-4e0b-9f9e-bbadffe4f202','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',126,'text','**Triết lý vận hành:** "Đánh chặn" trên Social mang lại quy mô, nhưng "Đón đầu" trên Search mới là cách mang về những ca điều trị có giá trị lớn với chi phí thu mua (CAC) tối ưu nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd718629-0d90-4fcc-b7be-bd519ea018a9','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',127,'text','Trong hệ điều hành Dental Empire OS, việc làm chủ lớp tìm kiếm không chỉ dừng lại ở SEO Google truyền thống, mà đã dịch chuyển mạnh mẽ sang Local SEO (Tìm kiếm địa phương) và GEO (Generative Engine Optimization - Tối ưu hóa cho các bộ máy tra cứu bằng AI).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('73b19268-02bc-48db-9abf-c740605a95e8','15-customer-journey','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',4,'Góc Nhìn Tâm Lý: Bệnh Nhân Đang Tìm Kiếm Điều Gì?','goc-nhin-tam-ly-benh-nhan-ang-tim-kiem-ieu-gi',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dd7b747-b410-4892-a13a-0014f63064d5','73b19268-02bc-48db-9abf-c740605a95e8',128,'text','Tâm lý khách hàng ở tầng này được chia làm hai nhóm rõ rệt: **Tìm kiếm giải pháp bệnh lý/chi phí** (Thông tin) và **Tìm kiếm đích danh thương hiệu** (Kiểm chứng cuối cùng). Họ thường xuyên gõ những cụm từ khóa mang tính quyết định:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36b6cbe9-ac2f-407e-8814-922b29315b45','73b19268-02bc-48db-9abf-c740605a95e8',129,'text','- *Nhu cầu khẩn cấp/Địa lý:* "Nha khoa gần đây", "Nha khoa uy tín tại Hà Nội".- *Khảo sát giải pháp & Chi phí:* "Trồng răng implant giá bao nhiêu?", "Bọc răng sứ có đau không?".- *Sàng lọc chất lượng:* "Niềng răng ở đâu tốt?", "Nên niềng Invisalign hay mắc cài?".- *Chốt chặn niềm tin (Branded Search):* "[Tên phòng khám của bạn] + review", "[Tên bác sĩ trưởng ca] + nha khoa".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ff8b88f4-35a1-4214-bc32-e404553ad8f5','15-customer-journey','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',4,'Hệ Thống Kênh Chủ Lực &amp; Ma Trận Nội Dung Đón Đầu Nhu Cầu','he-thong-kenh-chu-luc-amp-ma-tran-noi-dung-on-au-nhu-cau',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f377a402-fa56-4ffd-8091-08523db6effe','ff8b88f4-35a1-4214-bc32-e404553ad8f5',130,'text','Để xuất hiện ngay lập tức khi bệnh nhân phát ra tín hiệu tìm kiếm, phòng khám cần xây dựng một mạng lưới bao phủ toàn bộ các điểm chạm tra cứu thông tin:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56b72f9a-f7cd-493e-aedd-1e3945a649f0','ff8b88f4-35a1-4214-bc32-e404553ad8f5',131,'text','- **Hạ tầng kênh cốt lõi:** Google Search, Google Business Profile (Google Maps), Website chuẩn SEO, Hệ thống GEO Content (Nội dung tối ưu cho câu trả lời của AI như Gemini, Perplexity, ChatGPT Search).- **Cấu trúc nội dung chuẩn Search Layer:***Bài viết dịch vụ chuyên sâu:* Làm rõ quy trình, chi phí minh bạch, đối tượng phù hợp và chính sách bảo hành.- *Bài viết giải đáp (FAQ):* Trả lời trực diện, trung thực vào các câu hỏi hóc búa của bệnh nhân (Ví dụ: *Tác hại của việc trồng implant giá rẻ*).- *Trang hồ sơ Bác sĩ & Thư viện ca lâm sàng (Case study):* Sử dụng Review Schema (đoạn mã cấu trúc dữ liệu) để hiển thị số sao đánh giá ngay trên kết quả tìm kiếm Google.- *Nội dung so sánh khách quan:* Giúp khách hàng phân tích thiệt hơn giữa các phương án y khoa để họ tự đưa ra lựa chọn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a604fba9-8ee6-4dbf-a642-cae615342290','15-customer-journey','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',4,'Quy Trình Xử Lý Dòng Chảy Tìm Kiếm (Search Pipeline)','quy-trinh-xu-ly-dong-chay-tim-kiem-search-pipeline',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5165895-9754-4657-abac-8740d76da1fe','a604fba9-8ee6-4dbf-a642-cae615342290',132,'text','Chiếm lĩnh tầng Search Layer đòi hỏi một quy trình kỹ thuật bài bản, nhất quán giữa tư duy marketing và ngôn ngữ lâm sàng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d139a3ee-6f26-4dee-89f7-04985e035087','a604fba9-8ee6-4dbf-a642-cae615342290',133,'image',NULL,'book/15-customer-journey/773397e6-2152-4daa-b4ac-0bf39d6eccbf-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a33a6ef-63a2-4a16-8ec1-cbcfc07e4bde','15-customer-journey','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',4,'Phân Quyền Nhân Sự Và Bộ Chỉ Số Quản Trị Tầng Search','phan-quyen-nhan-su-va-bo-chi-so-quan-tri-tang-search',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d400eb33-1acf-44d1-99c4-d05518011493','9a33a6ef-63a2-4a16-8ec1-cbcfc07e4bde',134,'text','- **Nhân sự chịu trách nhiệm chính:** Khối **Marketing OS** (Chuyên viên SEO, Technical Marketer phụ trách Maps và Website).- **Nhân sự phối hợp thực chiến:** Data OS (Theo dõi nguồn và chất lượng lead), Sales OS (Tiếp nhận lead) và Bác sĩ chuyên môn (Cố vấn kiến thức để bài viết đạt tiêu chuẩn E-E-A-T của Google).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72ad2b66-6a7f-4ac5-afcb-3d41a89a308a','9a33a6ef-63a2-4a16-8ec1-cbcfc07e4bde',135,'image',NULL,'book/15-customer-journey/dc15d6a0-54b4-498e-88ca-37a933d263cc-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('165c544d-aed5-4be1-8ca3-08455c6c315d','9a33a6ef-63a2-4a16-8ec1-cbcfc07e4bde',136,'text','Hiệu quả của tầng Search Layer được minh bạch hóa qua các chỉ số trên Dashboard:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66d40928-c53b-4e83-b475-282c7a6f2af4','9a33a6ef-63a2-4a16-8ec1-cbcfc07e4bde',137,'text','- **Keyword Ranking: **Thứ hạng của các từ khóa dịch vụ (Implant, Niềng răng) trên top tìm kiếm.- **Organic Traffic: **Lượng truy cập tự nhiên, không tốn tiền quảng cáo vào Website phòng khám.- **Branded Search Volume: **Lượng tìm kiếm đích danh tên phòng khám/bác sĩ (Chỉ số này càng cao chứng tỏ thương hiệu càng mạnh).- **Google Map Actions: **Tổng số lượt bấm gọi điện, bấm nhắn tin hoặc bấm chỉ đường (Direction request) trên Maps.- **Search-to-lead Conversion: **Tỷ lệ khách truy cập từ tìm kiếm chuyển thành Lead (Điền form, gọi hotline).- **SEO Lead Quality: **Tỷ lệ lead từ search chuyển sang lịch hẹn (Thông thường, tỷ lệ này luôn cao gấp 1.5 - 2 lần so với lead từ social).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7b927721-2eb4-48a1-8110-e2719a9e66ee','15-customer-journey','2956f4b5-b96e-4aad-aae4-f1a4a3b7a15d',4,'Những Lỗi Chí Mạng Khiến Phòng Khám "Vô Hình" Trên Internet','nhung-loi-chi-mang-khien-phong-kham-vo-hinh-tren-internet',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89be3e85-8f44-478f-96a9-e4c98d8c392e','7b927721-2eb4-48a1-8110-e2719a9e66ee',138,'text','Rất nhiều chủ phòng khám đang vô tình cắt đứt dòng chảy khách hàng chất lượng cao này vì để hệ thống dính phải những sai lầm vận hành nghiêm trọng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a7d223e-3ce5-47b7-8858-1f903155b9e8','7b927721-2eb4-48a1-8110-e2719a9e66ee',139,'text','- **Bẫy "Chỉ làm Social, bỏ quên Search":** Đổ toàn bộ ngân sách vào xây kênh TikTok, chạy Ads Facebook nhưng Website bỏ hoang, Google Maps không tối ưu. Khi khách hàng xem video trên TikTok thấy hay, họ gõ Google để kiểm tra mà không thấy bạn đâu, họ sẽ lập tức chọn đối thủ.- **Bỏ quên Google Maps (Local SEO):** Không tối ưu hóa tài khoản Google Business Profile, khiến phòng khám không xuất hiện trong top 3 bản đồ khi khách hàng gõ "nha khoa gần đây". Bạn đang tự tay từ chối tệp khách hàng ngay trong bán kính 5km quanh mình.- **Website nghèo nàn, thiếu trang dịch vụ đích:** Khách bấm vào website chỉ thấy hình ảnh chung chung, không có bài viết chi tiết cho từng dịch vụ, không có bảng giá rõ ràng. Khách sẽ thoát trang sau 3 giây vì không tìm thấy thứ họ cần.- **Viết bài theo tư duy chủ quan, thiếu tracking:** Viết những bài viết quá hàn lâm mà bệnh nhân không bao giờ tìm kiếm. Đồng thời không cài đặt các công cụ đo lường (Google Analytics, Pixel) để biết lead đổ về từ bài viết nào, dẫn đến việc đầu tư mù quáng.- **Bỏ quên kỷ nguyên AI Search:** Không cấu trúc nội dung theo dạng câu hỏi - câu trả lời trực diện, khiến phòng khám hoàn toàn biến mất trong các câu trả lời đề xuất của robot AI (Gemini, ChatGPT) khi bệnh nhân tra cứu thông tin.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39296ad0-0a44-45c9-b8a7-5b6445737edc','7b927721-2eb4-48a1-8110-e2719a9e66ee',140,'text','Tầng Search Layer chính là nơi phân loại các phòng khám nha khoa làm thương hiệu hời hợt với những hệ thống vận hành bài bản. Khi bạn chiếm lĩnh được tầng này, phòng khám của bạn sẽ sở hữu một nguồn "tài sản chìm" vô giá, liên tục bơm vào hệ thống CRM những lead có tỷ lệ chốt cực cao, tạo bệ phóng vững chắc cho doanh thu của toàn bộ Clinic System.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4b58eb45-2130-489e-ae28-7db8a95478e2','15-customer-journey','7b165f0a-9f9a-4c17-8515-0562d96d9dd3',3,'Tầng 6: Conversion - Khúc cua quyết định đưa khách hàng đến phòng khám','tang-6-conversion-khuc-cua-quyet-inh-ua-khach-hang-en-phong-kham',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b9b0802-c152-48a9-bb07-ad52bddfe747','4b58eb45-2130-489e-ae28-7db8a95478e2',141,'text','Nếu toàn bộ các tầng trước từ Traffic, Trust cho đến Search Layer được ví như quá trình tiền đạo dẫn bóng qua hàng loạt hậu vệ đối phương, thì **Tầng 6 - Conversion (Chuyển đổi)** chính là cú sút quyết định để đưa bóng vào lưới. Đây là khoảnh khắc mà mọi nỗ lực truyền thông và nuôi dưỡng trước đó được đo lường bằng kết quả hữu hình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b806c9a-37a7-4362-ae15-2d7ef2a2f7c2','4b58eb45-2130-489e-ae28-7db8a95478e2',142,'text','Trong hệ điều hành Dental Empire OS, Conversion không đơn thuần là một con số phần trăm khô khan trên báo cáo. Đây là điểm chạm sinh tử biến một "người lạ đã chớm ấm" trên môi trường số trở thành một bệnh nhân thực sự bằng các hành động có giá trị cao: gọi điện hotline, điền form đăng ký, nhắn tin xác nhận, đặt lịch hẹn và quan trọng nhất là **bước chân đến phòng khám để nghe tư vấn và bắt đầu điều trị**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3f39372-022f-4744-8ffc-d6152ae7d5e5','4b58eb45-2130-489e-ae28-7db8a95478e2',143,'text','Làm tốt tầng này là cách bạn bảo vệ dòng tiền, đảm bảo chi phí Marketing bỏ ra không bị lãng phí ở phút chót.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bd32b685-07c8-4589-9f67-6db589315f13','15-customer-journey','4b58eb45-2130-489e-ae28-7db8a95478e2',4,'Góc Nhìn Tâm Lý: Sự Giằng Xé Trước Thềm Quyết Định','goc-nhin-tam-ly-su-giang-xe-truoc-them-quyet-inh',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78a37311-2ea6-4127-8d03-c283f0316091','bd32b685-07c8-4589-9f67-6db589315f13',144,'text','Bệnh nhân ở tầng Conversion đã đi qua bộ lọc kiểm chứng, họ không còn hoài nghi về năng lực của bạn nữa, nhưng họ lại phải đối mặt với nỗi sợ của chính mình. Sự chần chừ lúc này không nằm ở chỗ phòng khám có uy tín không, mà nằm ở tâm lý e ngại cá nhân. Trong đầu họ luôn có những tiếng nói xung đột:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7fd7b273-a7db-40e0-af00-59d42a7c312b','bd32b685-07c8-4589-9f67-6db589315f13',145,'text','- *"Hay là mình cứ đặt lịch khám thử xem sao, đằng nào cũng được tư vấn miễn phí."*- *"Mình muốn qua gặp trực tiếp vị bác sĩ trên video để xem răng mình có cứu được không."*- *"Biết là cần phải làm rồi, nhưng không biết chi phí thực tế khi khám xong có bị đội lên không?"*- *"Thực sự vẫn rất sợ đau, nhưng mình muốn nghe phác đồ cụ thể để chuẩn bị tâm lý."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66120d75-0255-45e8-8782-9527949df367','bd32b685-07c8-4589-9f67-6db589315f13',146,'text','Nhiệm vụ của đội ngũ vận hành tại điểm chạm này là đưa ra một "cú hích" đủ tinh tế, an toàn để họ dũng cảm bước qua nỗi sợ và đưa ra cam kết về mặt thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('91641682-8ed8-4a2d-95ab-eef82ce556b4','15-customer-journey','4b58eb45-2130-489e-ae28-7db8a95478e2',4,'Hệ Thống Kênh Tiếp Nhận Và Kho Tài Sản Trợ Lực Chốt Lịch','he-thong-kenh-tiep-nhan-va-kho-tai-san-tro-luc-chot-lich',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('847b6756-51ee-4050-a727-ae7c867e3785','91641682-8ed8-4a2d-95ab-eef82ce556b4',147,'text','Để không làm rơi rớt bất kỳ cơ hội chuyển đổi nào, toàn bộ các kênh tiếp nhận dữ liệu (Inbox, Hotline, Zalo OA, Website Form, Landing Page, Đường link đặt lịch tự động) phải được đổ thẳng về bộ não CRM và được hỗ trợ bởi khối tài sản thực chiến:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('afbc6dcd-845b-4b69-8fbf-a37783890604','91641682-8ed8-4a2d-95ab-eef82ce556b4',148,'text','- **Booking Script (Kịch bản chốt lịch hẹn):** Bộ quy tắc giao tiếp điều hướng khách chọn khung giờ cụ thể, tuyệt đối không hỏi câu hỏi mở dạng *"Khi nào anh chị qua được?"*.- **Offer tư vấn không thể từ chối:** Các đặc quyền dành riêng cho khách đặt lịch sớm (Ví dụ: *Tặng gói tầm soát bằng máy CT Cone Beam trị giá 1 triệu đồng cho 5 khách hàng đăng ký hôm nay*).- **Bảng hướng dẫn trước khi đến khám:** Sự chuẩn bị chu đáo (lưu ý ăn uống trước khi nhổ răng, hồ sơ bệnh lý cũ cần mang theo) thể hiện tính chuyên nghiệp của một cơ sở y tế đẳng cấp.- **Hệ thống định vị & Chỉ đường:** Tin nhắn Zalo tự động gửi sơ đồ đường đi, chỗ đỗ xe ô tô, hình ảnh mặt tiền phòng khám để triệt tiêu sự bối rối của khách khi tìm đường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ab1405f5-28d2-4db5-b52c-f877c15a5b38','15-customer-journey','4b58eb45-2130-489e-ae28-7db8a95478e2',4,'Quy Trình Xử Lý Dòng Chuyển Đổi (Conversion Pipeline)','quy-trinh-xu-ly-dong-chuyen-oi-conversion-pipeline',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2756d729-b302-4047-b941-32e499ddf3fd','ab1405f5-28d2-4db5-b52c-f877c15a5b38',149,'text','Một quy trình Conversion chuẩn mực trong nha khoa phải diễn ra như một băng chuyền công nghiệp, nhịp nhàng và chính xác tuyệt đối:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6891fd49-deef-43bd-aa1c-18ac56bcfcca','ab1405f5-28d2-4db5-b52c-f877c15a5b38',150,'image',NULL,'book/15-customer-journey/af95e42d-8ae9-44b6-a7e6-c581d4fa651f-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d4c170dc-bb65-43e7-b94c-0deed29ef940','15-customer-journey','4b58eb45-2130-489e-ae28-7db8a95478e2',4,'Phân Quyền Nhân Sự Và Bộ KPI Đo Lường Hiệu Suất Tầng Chốt','phan-quyen-nhan-su-va-bo-kpi-o-luong-hieu-suat-tang-chot',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d31c87b8-2b2d-49d2-aa73-eb95a36a197a','d4c170dc-bb65-43e7-b94c-0deed29ef940',151,'text','**Về cấu trúc nhân sự vận hành:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('517b739c-4b70-4b33-896e-24ce34f9d6d8','d4c170dc-bb65-43e7-b94c-0deed29ef940',152,'text','- **Nhân sự chịu trách nhiệm chính:** Khối **Sales OS** (Bao gồm đội ngũ Telesale, chuyên viên trực chat và bộ phận lễ tân điều phối). Đây là những người trực tiếp nắm giữ huyết mạch chuyển đổi, chịu trách nhiệm "bơm" khách đến phòng khám.- **Nhân sự phối hợp thực chiến:** Khối **Clinic OS** (Tiếp nhận dữ liệu để chuẩn bị sẵn sàng về ghế nha, vật tư và tâm thế đón tiếp), bộ phận **CSKH** (Hỗ trợ quy trình nhắc lịch) và **Data OS** (Theo dõi hành vi dịch chuyển của các con số trên phễu).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6df071b5-b297-4c07-b30d-0de059e5854b','d4c170dc-bb65-43e7-b94c-0deed29ef940',153,'image',NULL,'book/15-customer-journey/f9bbb929-2986-40e2-bc91-85c4491a29a4-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d60c1620-4597-4a47-9ac7-de9e402238a1','d4c170dc-bb65-43e7-b94c-0deed29ef940',154,'text','**Bộ chỉ số KPI đo lường hiệu suất:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('497ec911-1480-4079-b169-b6cada159698','d4c170dc-bb65-43e7-b94c-0deed29ef940',155,'text','Sức khỏe của tầng Conversion không được đánh giá bằng cảm giác, mà phải hiển thị rõ ràng trên Dashboard quản trị thông qua các chỉ số sinh tử sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('920a9bc6-accd-434b-b501-cd0c56cc9843','d4c170dc-bb65-43e7-b94c-0deed29ef940',156,'text','- **Booking Rate (Tỷ lệ đặt lịch):** Đo lường năng lực khơi gợi nhu cầu và chốt hẹn của đội ngũ trực chat/Telesale. Chỉ số này cho biết bao nhiêu phần trăm lượng lead đổ về từ hotline hay tin nhắn thực sự chuyển đổi thành một lịch hẹn có ngày, giờ và bác sĩ phụ trách cụ thể.- **Show-up Rate (Tỷ lệ đến khám):** Đây chính là chỉ số "sống còn" của tầng chốt. Nó phản ánh số lượng bệnh nhân thực sự bước chân qua cánh cửa phòng khám trên tổng số lịch đã hẹn. Một Show-up Rate cao là minh chứng cho thấy bộ máy đặt lịch và nhắc lịch đang vận hành cực kỳ hiệu quả.- **No-show Rate (Tỷ lệ bùng lịch):** Tỷ lệ khách hẹn nhưng không đến và không thông báo trước. Nếu con số này tăng vọt, đó là lời cảnh báo nghiêm trọng cho thấy khâu xây dựng giá trị cuộc hẹn của đội Sales đang quá lỏng lẻo, hoặc hệ thống tin nhắn nhắc lịch tự động đang gặp lỗi.- **Reschedule Rate (Tỷ lệ đổi lịch):** Đo lường số lượng khách hàng yêu cầu dời lịch hẹn sang một khung giờ hoặc ngày khác. Chỉ số này giúp nhà quản trị đánh giá tính linh hoạt của hệ thống điều phối lịch và mức độ bận rộn thực tế của tệp khách hàng.- **Treatment Acceptance Rate (Tỷ lệ đồng ý điều trị):** Điểm giao thoa quyết định giữa Sales và Lâm sàng. Chỉ số này đo lường bao nhiêu phần trăm bệnh nhân quyết định ký vào phác đồ, xuống tiền hoặc đặt cọc điều trị sau khi được Bác sĩ thăm khám và tư vấn trực tiếp tại ghế nha.- **Revenue per Booking (Doanh thu trên mỗi lượt đặt lịch):** Được tính bằng tổng doanh thu thực tế thu được chia cho tổng số lượt đặt lịch thành công. Chỉ số này giúp bạn đánh giá chính xác giá trị thương mại và chất lượng của mỗi cuộc hẹn được tạo ra từ Growth Engine.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3a9d3f2b-6614-4887-b434-f59cce834c61','15-customer-journey','4b58eb45-2130-489e-ae28-7db8a95478e2',4,'Những Cạm Bẫy Chết Người Khiến Phòng Khám "Đánh Rơi" Doanh Thu','nhung-cam-bay-chet-nguoi-khien-phong-kham-anh-roi-doanh-thu',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d05a0be-26db-4e67-a3d0-67e3979efcb8','3a9d3f2b-6614-4887-b434-f59cce834c61',157,'text','Rất nhiều chủ phòng khám RHM đau đầu vì chạy quảng cáo ra rất nhiều số điện thoại nhưng ghế nha vẫn trống. Đó là hậu quả của việc để lộ những lỗ hổng chí mạng trong quy trình chuyển đổi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9813c7ca-54a4-4efa-be8d-b4fc42fb615a','3a9d3f2b-6614-4887-b434-f59cce834c61',158,'text','- **Bẫy "Hẹn suông", thiếu cam kết:** Nhân viên chat với khách một hồi rồi kết luận: *"Dạ vâng khi nào anh rảnh anh qua em khám nhé"*. Đây là cách giết chết Conversion nhanh nhất. Một lịch hẹn chuẩn phải có **Ngày cụ thể - Giờ cụ thể - Bác sĩ phụ trách cụ thể**.- **Bỏ quên khâu xác nhận và nhắc lịch:** Khách hẹn từ đầu tuần nhưng đến cuối tuần phòng khám không có một tin nhắn, cuộc gọi nào nhắc nhớ. Khách hàng với cuộc sống bận rộn sẽ quên ngay lập tức, dẫn đến tỷ lệ No-show tăng vọt.- **Bỏ rơi khách hàng trước cửa phòng khám:** Không gửi hướng dẫn đường đi, không dặn dò trước khi đến khám. Khách đến nơi không tìm được nhà, không biết đỗ xe ở đâu, sinh ra tâm lý bực bội và sẵn sàng quay xe đi về.- **Sự đứt gãy khi bàn giao nội bộ (Handover Fail):** Sai lầm kinh điển của hệ thống là đội Sales online tư vấn cho khách một đằng, nhưng khi khách đến phòng khám, lễ tân và bác sĩ lâm sàng lại không hề nắm được thông tin, tiền sử bệnh lý và những thỏa thuận trước đó của khách. Việc bắt bệnh nhân phải khai báo lại từ đầu sẽ phá nát toàn bộ trải nghiệm và niềm tin họ tích lũy từ trước.- **Lười phân tích lý do khách "bùng lịch":** Thấy tỷ lệ khách không đến cao nhưng quản lý không ngồi lại phân tích nguyên nhân gốc rễ (do Sales hối thúc quá đà, do chọn sai khung giờ cao điểm, hay do kịch bản nhắc lịch quá thô cứng) để kịp thời sửa đổi hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1aa4a2d5-653c-44b8-9a25-e5e16b7224e8','3a9d3f2b-6614-4887-b434-f59cce834c61',159,'text','Khi bạn chuẩn hóa được tầng Conversion, bạn đang tạo ra một bộ lọc thép giúp phòng khám luôn chủ động được nguồn khách đến mỗi ngày. Từ đây, dòng chảy dữ liệu được bàn giao một cách hoàn hảo cho Clinic System, sẵn sàng biến những lời hứa trên môi trường số thành những trải nghiệm điều trị xuất sắc trên thực tế.',NULL,NULL,NULL,NULL,NULL);
